import type { Handler } from '../../src/types/api-handler.js';
import { requireAuth, json } from '../../src/lib/_auth.js';
import { getUserAccessToken, apiHost, headers } from '../../src/lib/_ebay.js';

export const handler: Handler = async (event) => {
	try {
		const auth = await requireAuth(event);
		if (!auth) return json({ error: 'unauthorized' }, 401);
		let token: string;
		try { token = await getUserAccessToken(auth.sub); } catch (e: any) {
			if (e?.code === 'ebay-not-connected') return json({ error: 'ebay-not-connected' }, 400);
			return json({ error: 'token-mint-failed', detail: e?.message || String(e) }, 500);
		}
		const host = apiHost();
		const h = headers(token);

		const body = event.body ? JSON.parse(event.body) : {};
		const reqKey = (body.merchantLocationKey || process.env.EBAY_MERCHANT_LOCATION_KEY || 'default-loc').toString();
		let reqAddr = body.address || null;
		// Fallback to environment-specified address if none provided
		if (!reqAddr) {
			const a1 = process.env.SHIP_ADDRESS1;
			const city = process.env.SHIP_CITY;
			const st = process.env.SHIP_STATE || process.env.SHIP_STATE_OR_PROVINCE;
			const pc = process.env.SHIP_POSTAL || process.env.SHIP_POSTAL_CODE;
			const ctry = process.env.SHIP_COUNTRY || 'US';
			if (a1 && city && st && pc) {
				reqAddr = { addressLine1: a1, city, stateOrProvince: st, postalCode: pc, country: ctry };
			}
		}

		// 1) If any location exists, return the first enabled one or first match by key
		const listUrl = `${host}/sell/inventory/v1/location?limit=200`;
		const listRes = await fetch(listUrl, { headers: h });
		const listTxt = await listRes.text();
		let listJson: any; try { listJson = JSON.parse(listTxt); } catch { listJson = { raw: listTxt }; }
		if (!listRes.ok) return json({ ok: false, error: 'list-locations-failed', status: listRes.status, detail: listJson }, listRes.status);
		const locations = Array.isArray(listJson?.locations) ? listJson.locations : [];

		const byKey = locations.find((l: any) => (l?.merchantLocationKey || '') === reqKey) || locations[0];
		if (byKey) {
			const key = byKey.merchantLocationKey || reqKey;
			const status = (byKey?.merchantLocationStatus || '').toUpperCase();
			if (status !== 'ENABLED') {
				// try to enable
				const enableUrl = `${host}/sell/inventory/v1/location/${encodeURIComponent(key)}/enable`;
				const enRes = await fetch(enableUrl, { method: 'POST', headers: h, body: JSON.stringify({}) });
				if (!(enRes.ok || enRes.status === 204)) {
					// Surface but still return key
					const enTxt = await enRes.text(); let enJ: any; try { enJ = JSON.parse(enTxt); } catch { enJ = { raw: enTxt }; }
					return json({ ok: false, error: 'enable-failed', status: enRes.status, detail: enJ });
				}
			}
			return json({ ok: true, merchantLocationKey: key });
		}

		// 2) None exist: require address to create
		if (!reqAddr || !reqAddr.addressLine1 || !reqAddr.city || !reqAddr.stateOrProvince || !reqAddr.postalCode || !reqAddr.country) {
			return json({ ok: false, error: 'missing-address', hint: 'Provide address { addressLine1, city, stateOrProvince, postalCode, country }' }, 400);
		}

		const createPayload = {
			name: process.env.SHIP_NAME || 'Default Location',
			merchantLocationKey: reqKey,
			merchantLocationStatus: 'ENABLED',
			locationTypes: ['WAREHOUSE'],
			location: { address: reqAddr },
		};
		const createUrl = `${host}/sell/inventory/v1/location`;
		const cRes = await fetch(createUrl, { method: 'POST', headers: h, body: JSON.stringify(createPayload) });
		if (cRes.status === 201 || cRes.status === 204 || cRes.status === 409) {
			return json({ ok: true, merchantLocationKey: reqKey });
		}
		const cTxt = await cRes.text(); let cJson: any; try { cJson = JSON.parse(cTxt); } catch { cJson = { raw: cTxt }; }
		return json({ ok: false, error: 'create-location-failed', status: cRes.status, detail: cJson }, cRes.status);
	} catch (e: any) {
		return json({ error: e?.message || String(e) }, 500);
	}
};

import type { Handler } from '../../src/types/api-handler.js';
import { accessTokenFromRefresh, tokenHosts } from '../../src/lib/_common.js';
import { tokensStore } from '../../src/lib/redis-store.js';
import { getBearerToken, getJwtSubUnverified, requireAuthVerified, userScopedKey } from '../../src/lib/_auth.js';

function tryJson(t: string) {
	try {
		return JSON.parse(t);
	} catch {
		return t;
	}
}

export const handler: Handler = async (event) => {
	try {
		// Auth check
		const bearer = getBearerToken(event);
		let sub = (await requireAuthVerified(event))?.sub || null;
		if (!sub) sub = getJwtSubUnverified(event);
		if (!bearer || !sub) {
			return {
				statusCode: 401,
				headers: { 'Content-Type': 'application/json' },
				body: JSON.stringify({ error: 'Unauthorized' }),
			};
		}

		// Use connected user's refresh token
		const store = tokensStore();
		const saved = (await store.get(userScopedKey(sub, 'ebay.json'), { type: 'json' })) as any;
		const refresh = saved?.refresh_token as string | undefined;
		if (!refresh)
			return {
				statusCode: 400,
				headers: { 'Content-Type': 'application/json' },
				body: JSON.stringify({ error: 'Connect eBay first' }),
			};
		const { access_token } = await accessTokenFromRefresh(refresh);

		const { apiHost } = tokenHosts(process.env.EBAY_ENV);
		const MARKETPLACE_ID = process.env.EBAY_MARKETPLACE_ID || 'EBAY_US';
		const qs = (event?.queryStringParameters || {}) as Record<string, string>;
		const keyRaw = qs['key'] || process.env.EBAY_MERCHANT_LOCATION_KEY || 'default-loc';
		// Normalize merchantLocationKey: eBay docs recommend no spaces; keep to [A-Za-z0-9-_]
		const key = String(keyRaw).trim().replace(/\s+/g, '-');

		const name = (qs['name'] || process.env.SHIP_NAME || '').toString().trim();
		const addressLine1 = (qs['address1'] || process.env.SHIP_ADDRESS1 || '').toString().trim();
		const city = (qs['city'] || process.env.SHIP_CITY || '').toString().trim();
		let stateOrProvince = (qs['state'] || process.env.SHIP_STATE || '').toString().trim();
		let postalCode = (qs['postal'] || process.env.SHIP_POSTAL || '').toString().trim();
		const country = ((qs['country'] || process.env.SHIP_COUNTRY || 'US') as string).toUpperCase();

		// Basic normalization for US addresses
		if (country === 'US') {
			stateOrProvince = stateOrProvince.toUpperCase();
			// Convert ZIP+4 with spaces to canonical 12345-1234 form if needed
			const zipMatch = postalCode.match(/^(\d{5})(?:[- ]?(\d{4}))?$/);
			if (zipMatch) {
				postalCode = zipMatch[2] ? `${zipMatch[1]}-${zipMatch[2]}` : zipMatch[1];
			}
		}

		if (!addressLine1 || !city || !stateOrProvince || !postalCode || !country) {
			return {
				statusCode: 400,
				headers: { 'Content-Type': 'application/json' },
				body: JSON.stringify({
					error: 'missing-address',
					message:
						'Please provide address1, city, state, postal, and country to initialize your ship-from location.',
					example:
						'/.netlify/functions/ebay-init-location?key=home&name=Home&address1=123%20Main%20St&city=Manchester&state=NH&postal=03101&country=US',
				}),
			};
		}

		const payload = {
			name: name || 'Default Location',
			merchantLocationStatus: 'ENABLED',
			location: { address: { addressLine1, city, stateOrProvince, postalCode, country } },
			merchantLocationKey: key,
		} as any;
		// Allow opting out of locationTypes via query (?omitTypes=true) to bypass validation edge cases
		const omitTypes = String(qs['omitTypes'] || 'false').toLowerCase() === 'true';
		if (!omitTypes) {
			(payload as any).locationTypes = ['WAREHOUSE']; // eBay allowed values: WAREHOUSE, STORE
		}

		// CREATE the location (POST /location/{merchantLocationKey})
		const url = `${apiHost}/sell/inventory/v1/location/${encodeURIComponent(key)}`;
		const r = await fetch(url, {
			method: 'POST',
			headers: {
				Authorization: `Bearer ${access_token}`,
				'Content-Type': 'application/json',
				Accept: 'application/json',
				'Accept-Language': 'en-US',
				'Content-Language': 'en-US',
				'X-EBAY-C-MARKETPLACE-ID': MARKETPLACE_ID,
			},
			body: JSON.stringify(payload),
		});

		const text = await r.text();
		let json: any;
		try {
			json = JSON.parse(text);
		} catch {
			json = { raw: text };
		}
		// Treat 201 Created or 409 Already Exists as success
		if (r.status === 201 || r.status === 409) {
			return {
				statusCode: 200,
				headers: { 'Content-Type': 'application/json' },
				body: JSON.stringify({ ok: true, key }),
			};
		}
		// Some accounts return 400 with errorId 25803 when the key already exists
		const errId = json?.errors?.[0]?.errorId;
		if (r.status === 400 && errId === 25803) {
			return {
				statusCode: 200,
				headers: { 'Content-Type': 'application/json' },
				body: JSON.stringify({ ok: true, key, exists: true, status: 409 }),
			};
		}
		// Otherwise, return detailed diagnostics
		return {
			statusCode: r.status,
			headers: { 'Content-Type': 'application/json' },
			body: JSON.stringify({
				error: 'create-location failed',
				status: r.status,
				url,
				payload,
				response: json,
			}),
		};
	} catch (e: any) {
		return {
			statusCode: 500,
			headers: { 'Content-Type': 'application/json' },
			body: JSON.stringify({ error: `init-location error: ${e.message}` }),
		};
	}
};

import type { Handler } from '../../src/types/api-handler.js';
import { accessTokenFromRefresh, tokenHosts } from "../../src/lib/_common.js";
import { tokensStore } from "../../src/lib/redis-store.js";
import { userScopedKey } from "../../src/lib/_auth.js";
import { getOrigin, isAuthorized, isOriginAllowed, jsonResponse } from "../../src/lib/http.js";
import { maybeRequireUserAuth } from "../../src/lib/auth-user.js";
import type { UserAuth } from "../../src/lib/auth-user.js";
import { mapGroupToDraftWithTaxonomy } from "../../src/lib/taxonomy-map.js";

type HeadersMap = Record<string, string | undefined>;

const METHODS = "POST, OPTIONS";

type DraftItem = {
  sku: string;
  title: string;
  price: number;
  quantity: number;
  imageUrls: string[];
  aspects?: Record<string, string[]>;
  inventoryCondition?: string;
  offerCondition?: number;
  categoryId?: string;
  description?: string;
  fulfillmentPolicyId?: string | null;
  paymentPolicyId?: string | null;
  returnPolicyId?: string | null;
  merchantLocationKey?: string | null;
  marketplaceId?: string;
  // Optional shipping weight (from wizard UI)
  weightLbs?: number;
  weightOz?: number;
};

type DraftMeta = {
  selectedCategory?: { id: string; slug: string; title: string } | null;
  missingRequired?: string[];
  marketplaceId?: string;
  categoryId?: string;
  price?: number;
};

type DraftPreview = {
  sku: string;
  title: string;
  price: number;
  quantity: number;
  categoryId?: string;
  marketplaceId?: string;
  imageUrls: string[];
  aspects: Record<string, string[]>;
};

type PolicyCache = {
  fulfillment: Map<string, string>;
  payment: Map<string, string>;
  return: Map<string, string>;
};

type EnvPolicies = {
  fulfillment?: string | null;
  payment?: string | null;
  return?: string | null;
};

type ProcessContext = {
  apiHost: string;
  baseHeaders: Record<string, string>;
  appBase: string | null;
  defaultCategoryId: string;
  defaultMarketplaceId: string;
  promotedCampaignId?: string | null;
  envPolicies: EnvPolicies;
  envLocationKey?: string | null;
  locationCache: Set<string>;
  policyCache: PolicyCache;
};

export const handler: Handler = async (event) => {
  const headers = event.headers as HeadersMap;
  const originHdr = getOrigin(headers);
  if (event.httpMethod === "OPTIONS") {
    return jsonResponse(200, {}, originHdr, METHODS);
  }

  if (event.httpMethod !== "POST") {
    return jsonResponse(405, { error: "Method not allowed" }, originHdr, METHODS);
  }

  const fetchSite = (headers["sec-fetch-site"] || headers["Sec-Fetch-Site"] || "")
    .toString()
    .toLowerCase();
  const originAllowed = isOriginAllowed(originHdr);
  if (!originAllowed && fetchSite !== "same-origin") {
    return jsonResponse(403, { error: "Forbidden" }, originHdr, METHODS);
  }

  let userAuth: UserAuth | null = null;
  if (!isAuthorized(headers)) {
    try {
      userAuth = await maybeRequireUserAuth(headers.authorization || headers.Authorization);
    } catch (err) {
      const reason = err instanceof Error ? err.message : String(err ?? "");
      console.warn("[ebay-create-draft] user auth failed", reason);
      return jsonResponse(401, { error: "Unauthorized" }, originHdr, METHODS);
    }
    if (!userAuth) {
      return jsonResponse(401, { error: "Unauthorized" }, originHdr, METHODS);
    }
  }

  let payload: any = {};
  if (event.body) {
    try {
      payload = JSON.parse(event.body);
    } catch {
      return jsonResponse(400, { error: "Invalid JSON" }, originHdr, METHODS);
    }
  }

  const initialItems: any[] = Array.isArray(payload?.items)
    ? payload.items
    : payload &&
        typeof payload === "object" &&
        !Array.isArray(payload) &&
        Object.keys(payload).length &&
        (payload as any).groups == null
      ? [payload]
      : [];

  const rawItems: any[] = [];
  const rawMeta: Array<DraftMeta | null> = [];

  initialItems.forEach((item) => {
    rawItems.push(item);
    rawMeta.push(extractMeta(item));
  });

  const invalid: Array<{ index: number; error: string; sku?: string; meta?: DraftMeta | null }> = [];

  if (Array.isArray(payload?.groups)) {
    const groupIndexBase = rawItems.length;
    for (let i = 0; i < payload.groups.length; i++) {
      const group = payload.groups[i];
      try {
        const mapped = await mapGroupToDraftWithTaxonomy(group);
        rawItems.push(mapped);
        rawMeta.push(extractMeta(mapped));
      } catch (err: any) {
        const message = err instanceof Error ? err.message : String(err);
        invalid.push({
          index: groupIndexBase + i,
          error: message,
          sku: groupSkuHint(group) || undefined,
          meta: extractMeta(group),
        });
      }
    }
  }

  if (!rawItems.length) {
    return jsonResponse(400, { error: "No items provided", invalid }, originHdr, METHODS);
  }

  const normalized: DraftItem[] = [];
  const normalizedMeta: Array<DraftMeta | null> = [];

  rawItems.forEach((item, idx) => {
    try {
      const mapped = normalizeItem(item);
      if (mapped) {
        normalized.push(mapped);
        normalizedMeta.push(rawMeta[idx] ?? extractMeta(item));
      } else {
        invalid.push({
          index: idx,
          error: "Item missing required fields",
          sku: captureSku(item) || undefined,
          meta: rawMeta[idx] ?? extractMeta(item),
        });
      }
    } catch (err: any) {
      const message = err instanceof Error ? err.message : String(err);
      const fallbackSku = captureSku(item);
      invalid.push({
        index: idx,
        error: message,
        sku: fallbackSku || undefined,
        meta: rawMeta[idx] ?? extractMeta(item),
      });
    }
  });

  if (!normalized.length) {
    const invalidSummaries = invalid.map((entry) => ({
      index: entry.index,
      error: entry.error,
      sku: entry.sku,
      meta: cleanMeta(entry.meta ?? null),
    }));
    return jsonResponse(400, { error: "No valid items", invalid: invalidSummaries }, originHdr, METHODS);
  }

  const invalidSummaries = invalid.map((entry) => ({
    index: entry.index,
    error: entry.error,
    sku: entry.sku,
    meta: cleanMeta(entry.meta ?? null),
  }));

  const appBase = deriveBaseUrlFromEvent(event);

  let refreshToken = (process.env.EBAY_REFRESH_TOKEN || "").trim();
  let refreshSource: "env" | "user" | "global" | null = refreshToken ? "env" : null;

  if (!refreshToken && userAuth?.userId) {
    try {
      const store = tokensStore();
      const saved = (await store.get(userScopedKey(userAuth.userId, "ebay.json"), { type: "json" })) as any;
      const candidate = typeof saved?.refresh_token === "string" ? saved.refresh_token.trim() : "";
      if (candidate) {
        refreshToken = candidate;
        refreshSource = "user";
      }
    } catch (err) {
      console.warn("[ebay-create-draft] failed to load user-scoped refresh token", err);
    }
  }

  if (!refreshToken) {
    try {
      const store = tokensStore();
      const saved = (await store.get("ebay.json", { type: "json" })) as any;
      const candidate = typeof saved?.refresh_token === "string" ? saved.refresh_token.trim() : "";
      if (candidate) {
        refreshToken = candidate;
        refreshSource = "global";
      }
    } catch (err) {
      console.warn("[ebay-create-draft] failed to load global refresh token", err);
    }
  }

  if (!refreshToken) {
    return jsonResponse(
      500,
      {
        error: "EBAY_REFRESH_TOKEN env var is required",
        detail: "Add EBAY_REFRESH_TOKEN in environment or connect eBay for this account.",
      },
      originHdr,
      METHODS,
    );
  }

  if (refreshSource) {
    console.log(
      JSON.stringify({ evt: "ebay.refreshToken.source", source: refreshSource, userId: userAuth?.userId || null }),
    );
  }

  let token: { access_token: string };
  try {
    token = await accessTokenFromRefresh(refreshToken);
  } catch (err: any) {
    const message = err instanceof Error ? err.message : String(err);
    return jsonResponse(500, { error: "Failed to refresh eBay token", detail: message }, originHdr, METHODS);
  }

  const ENV = (process.env.EBAY_ENV || "PROD").toUpperCase();
  const { apiHost } = tokenHosts(ENV);
  const defaultMarketplaceId = process.env.DEFAULT_MARKETPLACE_ID || process.env.EBAY_MARKETPLACE_ID || "EBAY_US";
  const defaultCategoryId = process.env.DEFAULT_CATEGORY_ID || "31413";
  const promotedCampaignId = process.env.PROMOTED_CAMPAIGN_ID || null;

  const baseHeaders: Record<string, string> = {
    Authorization: `Bearer ${token.access_token}`,
    "Content-Type": "application/json",
    Accept: "application/json",
    "Accept-Language": "en-US",
    "Content-Language": "en-US",
  };

  const context: ProcessContext = {
    apiHost,
    baseHeaders,
    appBase,
    defaultCategoryId,
    defaultMarketplaceId,
    promotedCampaignId,
    envPolicies: {
      fulfillment: process.env.EBAY_FULFILLMENT_POLICY_ID || null,
      payment: process.env.EBAY_PAYMENT_POLICY_ID || null,
      return: process.env.EBAY_RETURN_POLICY_ID || null,
    },
    envLocationKey: process.env.EBAY_MERCHANT_LOCATION_KEY || null,
    locationCache: new Set<string>(),
    policyCache: {
      fulfillment: new Map<string, string>(),
      payment: new Map<string, string>(),
      return: new Map<string, string>(),
    },
  };

  const successes: Array<{
    sku: string;
    offerId: string;
    status: string;
    offer: unknown;
    meta?: DraftMeta | null;
    draft?: DraftPreview;
  }> = [];
  const failures: Array<{
    sku: string;
    error: string;
    detail?: unknown;
    meta?: DraftMeta | null;
    draft?: DraftPreview;
  }> = invalidSummaries.map(
    (entry) => ({
      sku: entry.sku || `idx:${entry.index}`,
      error: entry.error,
      meta: entry.meta || null,
    })
  );

  for (let i = 0; i < normalized.length; i++) {
    const item = normalized[i];
    const meta = cleanMeta(normalizedMeta[i] ?? null);
    try {
      const result = await processItem(item, context);
      successes.push({ ...result, meta, draft: buildDraftPreview(item) });
    } catch (err: any) {
      const message = err instanceof Error ? err.message : String(err);
      failures.push({ sku: item.sku, error: message, detail: err?.detail, meta, draft: buildDraftPreview(item) });
    }
  }

  console.log(
    JSON.stringify({
      evt: "ebay.createDraft",
      dryRun: false,
      created: successes.length,
      failures: failures.length,
      invalid: invalidSummaries.length,
      userId: userAuth?.userId || null,
    }),
  );

  const ok = successes.length > 0;

  return jsonResponse(
    200,
    {
      ok,
      dryRun: false,
      created: successes.length,
      results: successes,
      failures,
      invalid: invalidSummaries,
    },
    originHdr,
    METHODS
  );
};

function normalizeItem(raw: any): DraftItem {
  if (!raw || typeof raw !== "object") throw new Error("Invalid item payload");
  const inventory = raw.inventory || {};
  const product = inventory.product || {};
  const offer = raw.offer || {};

  const sku = sanitizeSku(offer.sku || raw.sku);
  if (!sku) throw new Error("Missing sku");

  const title = String(product.title || offer.title || raw.title || "").trim();
  if (!title) throw new Error("Missing title");

  const price = Number(offer.price ?? raw.price ?? 0);
  if (!Number.isFinite(price) || price <= 0) throw new Error("Missing price");

  let imagesSource = Array.isArray(product.imageUrls)
    ? product.imageUrls
    : Array.isArray(raw.imageUrls)
      ? raw.imageUrls
      : [];
  if (!imagesSource.length) {
    if (Array.isArray((raw as any).images)) {
      imagesSource = (raw as any).images;
    } else if (typeof (raw as any).images === "string") {
      imagesSource = ((raw as any).images as string)
        .split(",")
        .map((s: string) => s.trim())
        .filter(Boolean);
    }
  }
  const imageUrls = imagesSource
    .filter((url: unknown) => typeof url === "string" && url.trim())
    .map((url: unknown) => String(url as string).trim())
    .slice(0, 12);
  if (!imageUrls.length) throw new Error("Missing images");

  const qtyRaw = Number(offer.quantity ?? raw.quantity ?? raw.qty ?? 1);
  const quantity = Number.isFinite(qtyRaw) && qtyRaw > 0 ? Math.trunc(qtyRaw) : 1;

  const aspects = normalizeAspects(product.aspects || raw.aspects);
  const conditionRaw = inventory.condition ?? offer.condition ?? raw.condition ?? "NEW";
  const { inventoryCondition, offerCondition } = normalizeCondition(conditionRaw);

  const categoryId = offer.categoryId || raw.categoryId || undefined;
  const marketplaceId = offer.marketplaceId || raw.marketplaceId || undefined;
  const description = product.description || offer.description || raw.description || title;
  const merchantLocationKey =
    offer.merchantLocationKey || offer.locationKey || raw.merchantLocationKey || raw.locationKey || null;

  // Optional weight from payload (separate lbs/oz from wizard)
  const weightLbsRaw = Number((raw as any).weightLbs ?? (offer as any)?.weightLbs ?? 0);
  const weightOzRaw = Number((raw as any).weightOz ?? (offer as any)?.weightOz ?? 0);
  const weightLbs = Number.isFinite(weightLbsRaw) && weightLbsRaw > 0 ? Math.round(weightLbsRaw * 100) / 100 : undefined;
  const weightOz = Number.isFinite(weightOzRaw) && weightOzRaw > 0 ? Math.round(weightOzRaw * 10) / 10 : undefined;

  return {
    sku,
    title,
    price: Math.round(price * 100) / 100,
    quantity,
    imageUrls,
    aspects,
    inventoryCondition,
    offerCondition,
    categoryId,
    description,
    fulfillmentPolicyId: offer.fulfillmentPolicyId || raw.fulfillmentPolicyId || null,
    paymentPolicyId: offer.paymentPolicyId || raw.paymentPolicyId || null,
    returnPolicyId: offer.returnPolicyId || raw.returnPolicyId || null,
    merchantLocationKey: merchantLocationKey ? String(merchantLocationKey) : null,
    marketplaceId,
    ...(weightLbs != null || weightOz != null ? { weightLbs, weightOz } : {}),
  };
}

function extractMeta(raw: unknown): DraftMeta | null {
  if (!raw || typeof raw !== "object") return null;
  const meta = (raw as any)._meta;
  if (!meta || typeof meta !== "object") return null;

  const candidate: DraftMeta = {};

  if (meta.selectedCategory && typeof meta.selectedCategory === "object") {
    const source = meta.selectedCategory as Record<string, unknown>;
    const idValue = source.id ?? source.categoryId;
    if (idValue) {
      const id = String(idValue);
      const slug = source.slug ? String(source.slug) : id;
      const title = source.title ? String(source.title) : slug;
      candidate.selectedCategory = { id, slug, title };
    }
  }

  if (Array.isArray(meta.missingRequired)) {
    candidate.missingRequired = meta.missingRequired.map((entry: unknown) => String(entry)).filter(Boolean);
  }

  if (meta.marketplaceId) candidate.marketplaceId = String(meta.marketplaceId);
  if (meta.categoryId) candidate.categoryId = String(meta.categoryId);
  if (typeof meta.price === "number" && Number.isFinite(meta.price)) candidate.price = meta.price;

  return cleanMeta(candidate);
}

function cleanMeta(meta: DraftMeta | null): DraftMeta | null {
  if (!meta) return null;
  const out: DraftMeta = {};
  if (meta.selectedCategory && meta.selectedCategory.id) {
    const id = meta.selectedCategory.id;
    const slug = meta.selectedCategory.slug || id;
    const title = meta.selectedCategory.title || slug;
    out.selectedCategory = { id, slug, title };
  }
  if (Array.isArray(meta.missingRequired) && meta.missingRequired.length) {
    const dedup = Array.from(new Set(meta.missingRequired.map((entry) => String(entry).trim()).filter(Boolean)));
    if (dedup.length) out.missingRequired = dedup;
  }
  if (meta.marketplaceId) out.marketplaceId = meta.marketplaceId;
  if (meta.categoryId) out.categoryId = meta.categoryId;
  if (typeof meta.price === "number" && Number.isFinite(meta.price)) out.price = meta.price;
  return Object.keys(out).length ? out : null;
}

function missingFromAspects(aspects?: Record<string, string[] | undefined> | undefined): string[] {
  if (!aspects) return [];
  return Object.entries(aspects)
    .filter(([, values]) => Array.isArray(values) && values.length === 0)
    .map(([name]) => name);
}

function mergeMeta(meta: DraftMeta | null | undefined, item: DraftItem): DraftMeta | null {
  const cleaned = cleanMeta(meta ?? null);
  const merged: DraftMeta = cleaned ? { ...cleaned } : {};
  const missing = missingFromAspects(item.aspects);
  if (missing.length) {
    const set = new Set((merged.missingRequired || []).map((entry) => entry));
    missing.forEach((entry) => set.add(entry));
    merged.missingRequired = Array.from(set);
  }
  if (!merged.marketplaceId && item.marketplaceId) merged.marketplaceId = item.marketplaceId;
  if (!merged.categoryId && item.categoryId) merged.categoryId = item.categoryId;
  if (!merged.selectedCategory && item.categoryId) {
    merged.selectedCategory = { id: item.categoryId, slug: item.categoryId, title: item.categoryId };
  }
  if (typeof item.price === "number" && Number.isFinite(item.price)) merged.price = item.price;
  return cleanMeta(merged);
}

function buildDraftPreview(item: DraftItem): DraftPreview {
  return {
    sku: item.sku,
    title: item.title,
    price: item.price,
    quantity: item.quantity,
    categoryId: item.categoryId,
    marketplaceId: item.marketplaceId,
    imageUrls: item.imageUrls,
    aspects: item.aspects || {},
  };
}

function sanitizeSku(value: unknown): string | null {
  if (!value) return null;
  const cleaned = String(value)
    .replace(/[^A-Za-z0-9]/g, "")
    .slice(0, 50);
  return cleaned || null;
}

function captureSku(raw: unknown): string | null {
  try {
    if (!raw || typeof raw !== "object") return null;
    const data = raw as Record<string, unknown>;
    const offer = typeof data.offer === "object" && data.offer ? (data.offer as Record<string, unknown>) : undefined;
    const candidate = offer?.sku ?? data.sku;
    return sanitizeSku(candidate);
  } catch {
    return null;
  }
}

function groupSkuHint(raw: any): string | null {
  if (!raw || typeof raw !== "object") return null;
  const candidate = raw.sku || raw.groupId || raw.id;
  if (candidate && typeof candidate === "string") {
    return candidate.slice(0, 50);
  }
  return null;
}

function normalizeCondition(value: unknown): { inventoryCondition?: string; offerCondition?: number } {
  if (typeof value === "number" && Number.isFinite(value)) {
    return {
      inventoryCondition: mapCondToInventory(Number(value)) ?? undefined,
      offerCondition: Number(value),
    };
  }
  if (typeof value === "string") {
    const trimmed = value.trim();
    if (!trimmed) return {};
    const numeric = Number(trimmed);
    if (Number.isFinite(numeric)) {
      return {
        inventoryCondition: mapCondToInventory(numeric) ?? undefined,
        offerCondition: numeric,
      };
    }
    const upper = trimmed.toUpperCase();
    return {
      inventoryCondition: upper || undefined,
      offerCondition: conditionStringToCode(upper),
    };
  }
  return {};
}

function mapCondToInventory(code?: number): string | undefined {
  switch (code) {
    case 1000:
      return "NEW";
    case 1500:
      return "NEW_OTHER";
    case 1750:
      return "NEW_WITH_DEFECTS";
    case 2000:
      return "CERTIFIED_REFURBISHED";
    case 2500:
      return "SELLER_REFURBISHED";
    case 2750:
      return "LIKE_NEW";
    case 3000:
      return "USED";
    case 4000:
      return "VERY_GOOD";
    case 5000:
      return "GOOD";
    case 6000:
      return "ACCEPTABLE";
    case 7000:
      return "FOR_PARTS_OR_NOT_WORKING";
    default:
      return undefined;
  }
}

function conditionStringToCode(value: string): number | undefined {
  switch (value.toUpperCase()) {
    case "NEW":
      return 1000;
    case "NEW_OTHER":
    case "NEW OTHER":
    case "NEW OTHER (SEE DETAILS)":
      return 1500;
    case "NEW_WITH_DEFECTS":
      return 1750;
    case "CERTIFIED_REFURBISHED":
    case "CERTIFIED REFURBISHED":
      return 2000;
    case "SELLER_REFURBISHED":
      return 2500;
    case "LIKE_NEW":
    case "LIKE NEW":
      return 2750;
    case "USED":
      return 3000;
    case "VERY_GOOD":
    case "VERY GOOD":
      return 4000;
    case "GOOD":
      return 5000;
    case "ACCEPTABLE":
      return 6000;
    case "FOR_PARTS_OR_NOT_WORKING":
    case "FOR PARTS OR NOT WORKING":
      return 7000;
    default:
      return undefined;
  }
}

function normalizeAspects(input: unknown): Record<string, string[]> | undefined {
  if (!input || typeof input !== "object") return undefined;
  const out: Record<string, string[]> = {};
  Object.entries(input as Record<string, unknown>).forEach(([key, value]) => {
    if (!key) return;
    const values = Array.isArray(value) ? value : [value];
    const normalized = values
      .map((entry) => (entry == null ? "" : String(entry).trim()))
      .filter(Boolean);
    if (normalized.length || (Array.isArray(value) && value.length === 0)) {
      out[String(key).trim()] = normalized;
    }
  });
  return Object.keys(out).length ? out : undefined;
}

function deriveBaseUrlFromEvent(event: any): string | null {
  try {
    const hdrs = event?.headers || {};
    const proto = (hdrs["x-forwarded-proto"] || hdrs["X-Forwarded-Proto"] || "https") as string;
    const host = (hdrs["x-forwarded-host"] || hdrs["X-Forwarded-Host"] || hdrs.host || hdrs.Host) as string;
    if (host) return `${proto}://${host}`;
  } catch {
    // ignore derivation errors
  }
  return null;
}

function toDirectDropbox(input: string): string {
  try {
    const url = new URL(input);
    if (url.hostname === "www.dropbox.com" || url.hostname === "dropbox.com") {
      url.hostname = "dl.dropboxusercontent.com";
      const qp = new URLSearchParams(url.search);
      qp.delete("dl");
      const qs = qp.toString();
      url.search = qs ? `?${qs}` : "";
      return url.toString();
    }
    return input;
  } catch {
    return input;
  }
}

async function processItem(item: DraftItem, ctx: ProcessContext) {
  const marketplaceId = item.marketplaceId || ctx.defaultMarketplaceId;
  const headers = makeHeaders(ctx.baseHeaders, marketplaceId);
  const imageUrls = await validateAndMaybeProxy(item.imageUrls, ctx.appBase);

  const inventoryPayload: Record<string, unknown> = {
    sku: item.sku,
    product: {
      title: item.title,
      description: item.description || item.title,
      imageUrls,
    },
    availability: { shipToLocationAvailability: { quantity: item.quantity } },
  };
  // If weight was provided, set package weight in ounces to satisfy shipping requirements
  try {
    const lbs = Number(item.weightLbs ?? 0);
    const oz = Number(item.weightOz ?? 0);
    const totalOz = (Number.isFinite(lbs) && lbs > 0 ? lbs * 16 : 0) + (Number.isFinite(oz) && oz > 0 ? oz : 0);
    if (totalOz > 0) {
      const rounded = Math.round(totalOz * 10) / 10; // 0.1 oz precision
      (inventoryPayload as any).packageWeightAndSize = {
        weight: { value: rounded, unit: 'OUNCE' },
      };
    }
  } catch {
    // ignore weight issues
  }
  if (item.inventoryCondition) inventoryPayload.condition = item.inventoryCondition;
  if (item.aspects) {
    console.log(`[processItem] Adding aspects for SKU ${item.sku}:`, JSON.stringify(item.aspects, null, 2));
    console.log(`[processItem] Has Brand? ${!!item.aspects.Brand}, Brand value:`, item.aspects.Brand);
    (inventoryPayload.product as any).aspects = item.aspects;
  } else {
    console.warn(`[processItem] NO ASPECTS for SKU ${item.sku}!`);
  }

  console.log(`[processItem] Sending inventory PUT for SKU ${item.sku} with payload:`, JSON.stringify(inventoryPayload, null, 2));

  const invUrl = `${ctx.apiHost}/sell/inventory/v1/inventory_item/${encodeURIComponent(item.sku)}`;
  const invRes = await fetch(invUrl, {
    method: "PUT",
    headers,
    body: JSON.stringify(inventoryPayload),
  });
  if (!invRes.ok) {
    const errorDetail = await safeBody(invRes);
    console.error(`[processItem] Inventory PUT failed for SKU ${item.sku}:`, errorDetail);
    throw buildError("inventory put failed", {
      step: "put-inventory-item",
      status: invRes.status,
      detail: await safeBody(invRes),
    });
  }

  const mlkBase = item.merchantLocationKey || ctx.envLocationKey;
  if (!mlkBase) {
    throw buildError("missing-location", {
      step: "get-location",
      detail: "No inventory location specified. Please set a default location in Settings.",
    });
  }
  const merchantLocationKey = mlkBase.trim().replace(/\s+/g, "-");
  if (!ctx.locationCache.has(merchantLocationKey)) {
    const locUrl = `${ctx.apiHost}/sell/inventory/v1/location/${encodeURIComponent(
      merchantLocationKey
    )}`;
    const locRes = await fetch(locUrl, { headers });
    if (locRes.status === 404) {
      throw buildError("missing-location", {
        step: "get-location",
        location: merchantLocationKey,
        detail: await safeBody(locRes),
      });
    }
    if (!locRes.ok) {
      throw buildError("location check failed", {
        step: "get-location",
        status: locRes.status,
        detail: await safeBody(locRes),
      });
    }
    ctx.locationCache.add(merchantLocationKey);
  }

  const fulfillmentPolicyId =
    item.fulfillmentPolicyId ||
    ctx.envPolicies.fulfillment ||
    (await resolvePolicy(
      ctx.policyCache.fulfillment,
      marketplaceId,
      () => pickPolicy(ctx.apiHost, headers, "/sell/account/v1/fulfillment_policy", marketplaceId)
    ));
  const paymentPolicyId =
    item.paymentPolicyId ||
    ctx.envPolicies.payment ||
    (await resolvePolicy(
      ctx.policyCache.payment,
      marketplaceId,
      () => pickPolicy(ctx.apiHost, headers, "/sell/account/v1/payment_policy", marketplaceId)
    ));
  const returnPolicyId =
    item.returnPolicyId ||
    ctx.envPolicies.return ||
    (await resolvePolicy(
      ctx.policyCache.return,
      marketplaceId,
      () => pickPolicy(ctx.apiHost, headers, "/sell/account/v1/return_policy", marketplaceId)
    ));

  if (!fulfillmentPolicyId || !paymentPolicyId || !returnPolicyId) {
    throw buildError("missing-policies", {
      step: "ensure-policies",
      marketplaceId,
    });
  }

  const offerPayload: Record<string, unknown> = {
    sku: item.sku,
    marketplaceId,
    format: "FIXED_PRICE",
    availableQuantity: item.quantity,
    categoryId: item.categoryId || ctx.defaultCategoryId,
    listingDescription: item.description || item.title,
    pricingSummary: { price: { currency: "USD", value: item.price.toFixed(2) } },
    listingPolicies: {
      fulfillmentPolicyId,
      paymentPolicyId,
      returnPolicyId,
    },
    merchantLocationKey,
  };
  if (item.offerCondition) offerPayload.condition = item.offerCondition;
  if (ctx.promotedCampaignId) offerPayload.appliedPromotionIds = [ctx.promotedCampaignId];

  const offerUrl = `${ctx.apiHost}/sell/inventory/v1/offer`;
  const offerRes = await fetch(offerUrl, {
    method: "POST",
    headers,
    body: JSON.stringify(offerPayload),
  });
  const offerBody = await safeBody(offerRes);
  if (!offerRes.ok) {
    throw buildError("offer create failed", {
      step: "post-offer",
      status: offerRes.status,
      detail: offerBody,
    });
  }

  const offerId = (offerBody as any)?.offerId || (offerBody as any)?.offer?.offerId;
  if (!offerId) {
    throw buildError("offer missing id after create", {
      step: "verify-offer",
      detail: offerBody,
    });
  }

  const verifyUrl = `${ctx.apiHost}/sell/inventory/v1/offer/${encodeURIComponent(offerId)}`;
  const verifyRes = await fetch(verifyUrl, { headers });
  const verifyBody = await safeBody(verifyRes);
  if (!verifyRes.ok) {
    throw buildError("offer verification failed", {
      step: "verify-offer",
      status: verifyRes.status,
      offerId,
      detail: verifyBody,
    });
  }

  return {
    sku: item.sku,
    offerId,
    status: (verifyBody as any)?.status ?? "UNKNOWN",
    offer: verifyBody,
  };
}

async function validateAndMaybeProxy(urls: string[], appBase: string | null): Promise<string[]> {
  const out: string[] = [];
  const base = appBase ? appBase.replace(/\/$/, "") : "";
  const isProxy = (u: string) => /\/\.netlify\/functions\/image-proxy/i.test(u);
  const absolutizeProxy = (u: string) => {
    if (u.startsWith("/") && base) return `${base}${u}`;
    return u;
  };
  const addBust = (u: string) => {
    try {
      const url = new URL(u, base || undefined);
      url.searchParams.set("v", Date.now().toString(36));
      return url.toString();
    } catch {
      return `${u}${u.includes("?") ? "&" : "?"}v=${Date.now().toString(36)}`;
    }
  };
  const maybeProxy = (source: string) => {
    if (isProxy(source)) return addBust(absolutizeProxy(source));
    const direct = toDirectDropbox(source);
    if (isProxy(direct)) return addBust(absolutizeProxy(direct));
    try {
      const url = new URL(direct);
      if (/(^|\.)dropbox\.com$/i.test(url.hostname)) {
        const prox = base
          ? `${base}/.netlify/functions/image-proxy?url=${encodeURIComponent(direct)}`
          : `/.netlify/functions/image-proxy?url=${encodeURIComponent(direct)}`;
        return addBust(absolutizeProxy(prox));
      }
    } catch {
      // ignore parse issues
    }
    return addBust(direct);
  };

  for (const src of urls) {
    const normalized = maybeProxy(String(src));
    try {
      const head = await fetch(normalized, { method: "HEAD", redirect: "follow" });
      const ct = (head.headers.get("content-type") || "").toLowerCase();
      if (head.ok && (!ct || ct.startsWith("image/"))) {
        out.push(normalized);
        continue;
      }
    } catch {
      // ignore failures during validation
    }
    out.push(normalized);
  }

  return Array.from(new Set(out)).slice(0, 12);
}

async function pickPolicy(
  apiHost: string,
  headers: Record<string, string>,
  path: string,
  marketplaceId: string
): Promise<string | null> {
  const url = `${apiHost}${path}?marketplace_id=${marketplaceId}`;
  const res = await fetch(url, { headers });
  const body = await safeBody(res);
  if (!res.ok) {
    return null;
  }
  const list =
    (body as any).fulfillmentPolicies ||
    (body as any).paymentPolicies ||
    (body as any).returnPolicies ||
    [];
  if (!Array.isArray(list) || !list.length) return null;
  const first = list[0];
  return (
    first?.id ||
    first?.fulfillmentPolicyId ||
    first?.paymentPolicyId ||
    first?.returnPolicyId ||
    null
  );
}

async function resolvePolicy(
  cache: Map<string, string>,
  marketplaceId: string,
  loader: () => Promise<string | null>
): Promise<string | null> {
  if (cache.has(marketplaceId)) {
    return cache.get(marketplaceId) || null;
  }
  const value = await loader();
  if (value) cache.set(marketplaceId, value);
  return value;
}

function makeHeaders(base: Record<string, string>, marketplaceId: string) {
  return { ...base, "X-EBAY-C-MARKETPLACE-ID": marketplaceId };
}

async function safeBody(res: Response): Promise<unknown> {
  const text = await res.text().catch(() => "");
  try {
    return text ? JSON.parse(text) : {};
  } catch {
    return text;
  }
}

function buildError(message: string, detail?: unknown) {
  const err = new Error(message);
  (err as any).detail = detail;
  return err;
}

import type { Handler } from '../../src/types/api-handler.js';
import { putInventoryItem } from '../../src/lib/ebay-sell.js';
import { accessTokenFromRefresh, tokenHosts } from '../../src/lib/_common.js';
import { tokensStore } from '../../src/lib/redis-store.js';
import { getBearerToken, getJwtSubUnverified, requireAuthVerified, userScopedKey } from '../../src/lib/_auth.js';
import { getOrigin, isAuthorized, isOriginAllowed, jsonResponse } from '../../src/lib/http.js';
import { maybeRequireUserAuth } from '../../src/lib/auth-user.js';
import type { UserAuth } from '../../src/lib/auth-user.js';

const METHODS = 'POST, OPTIONS';

export const handler: Handler = async (event) => {
  const headers = event.headers as Record<string, string | undefined>;
  const originHdr = getOrigin(headers);
  
  if (event.httpMethod === 'OPTIONS') {
    return jsonResponse(200, { ok: true }, originHdr, METHODS);
  }
  
  if (event.httpMethod !== 'POST') {
    return jsonResponse(405, { error: 'Method not allowed' }, originHdr, METHODS);
  }

  // Check authorization
  const fetchSite = (headers['sec-fetch-site'] || headers['Sec-Fetch-Site'] || '')
    .toString()
    .toLowerCase();
  const originAllowed = isOriginAllowed(originHdr);
  if (!originAllowed && fetchSite !== 'same-origin') {
    return jsonResponse(403, { error: 'Forbidden' }, originHdr, METHODS);
  }

  let userAuth: UserAuth | null = null;
  if (!isAuthorized(headers)) {
    try {
      userAuth = await maybeRequireUserAuth(headers.authorization || headers.Authorization);
    } catch (err) {
      console.warn('[ebay-fix-draft-aspects] user auth failed', err);
      return jsonResponse(401, { error: 'Unauthorized' }, originHdr, METHODS);
    }
    if (!userAuth) {
      return jsonResponse(401, { error: 'Unauthorized' }, originHdr, METHODS);
    }
  }

  let body: any = {};
  try {
    body = JSON.parse(event.body || '{}');
  } catch {
    return jsonResponse(400, { error: 'Invalid JSON' }, originHdr, METHODS);
  }

  const offerId = typeof body.offerId === 'string' ? body.offerId.trim() : '';
  if (!offerId) {
    return jsonResponse(400, { error: 'offerId required' }, originHdr, METHODS);
  }

  console.log('[ebay-fix-draft-aspects] Processing offerId:', offerId, 'userId:', userAuth?.userId || 'global');

  try {
    // Get eBay refresh token using user-scoped storage
    const bearer = getBearerToken(event);
    let sub = (await requireAuthVerified(event))?.sub || null;
    if (!sub) sub = getJwtSubUnverified(event);
    
    let refreshToken = (process.env.EBAY_REFRESH_TOKEN || '').trim();
    let refreshSource: 'env' | 'user' | null = refreshToken ? 'env' : null;

    if (!refreshToken && sub) {
      try {
        const store = tokensStore();
        const saved = (await store.get(userScopedKey(sub, 'ebay.json'), { type: 'json' })) as any;
        const candidate = typeof saved?.refresh_token === 'string' ? saved.refresh_token.trim() : '';
        if (candidate) {
          refreshToken = candidate;
          refreshSource = 'user';
        }
      } catch (err) {
        console.warn('[ebay-fix-draft-aspects] failed to load user-scoped refresh token', err);
      }
    }

    if (!refreshToken) {
      return jsonResponse(500, { error: 'No eBay credentials - connect eBay first' }, originHdr, METHODS);
    }

    console.log('[ebay-fix-draft-aspects] Using refresh token from:', refreshSource);

    const { access_token } = await accessTokenFromRefresh(refreshToken);
    const ENV = process.env.EBAY_ENV || 'PROD';
    const { apiHost } = tokenHosts(ENV);

    // Fetch the current offer
    console.log('[ebay-fix-draft-aspects] Fetching offer:', offerId);
    const offerUrl = `${apiHost}/sell/inventory/v1/offer/${encodeURIComponent(offerId)}`;
    const offerRes = await fetch(offerUrl, {
      headers: {
        'Authorization': `Bearer ${access_token}`,
        'Content-Type': 'application/json',
      },
    });

    if (!offerRes.ok) {
      const detail = await offerRes.text().catch(() => '');
      console.error('[ebay-fix-draft-aspects] Failed to fetch offer:', offerRes.status, detail);
      return jsonResponse(400, { error: 'Failed to fetch offer', status: offerRes.status, detail }, originHdr, METHODS);
    }

    const offer = await offerRes.json();
    const sku = offer.sku;
    if (!sku) {
      console.error('[ebay-fix-draft-aspects] Offer has no SKU:', offer);
      return jsonResponse(400, { error: 'Offer has no SKU', offer }, originHdr, METHODS);
    }

    console.log('[ebay-fix-draft-aspects] Fetching inventory for SKU:', sku);
    // Fetch current inventory item
    const inventoryUrl = `${apiHost}/sell/inventory/v1/inventory_item/${encodeURIComponent(sku)}`;
    const inventoryRes = await fetch(inventoryUrl, {
      headers: {
        'Authorization': `Bearer ${access_token}`,
      },
    });

    if (!inventoryRes.ok) {
      const detail = await inventoryRes.text().catch(() => '');
      console.error('[ebay-fix-draft-aspects] Failed to fetch inventory:', inventoryRes.status, detail);
      return jsonResponse(400, { error: 'Failed to fetch inventory', status: inventoryRes.status, detail }, originHdr, METHODS);
    }

    const inventory = await inventoryRes.json();
    const aspects = inventory.product?.aspects || {};
    const added: string[] = [];

    // Add missing common required aspects
    const defaults: Record<string, string> = {
      'Brand': 'Unbranded',
      'Type': 'Other',
      'Model': 'Does Not Apply',
      'MPN': 'Does Not Apply',
      'UPC': 'Does Not Apply',
    };

    for (const [name, defaultValue] of Object.entries(defaults)) {
      if (!aspects[name] || aspects[name].length === 0 || !aspects[name][0]?.trim()) {
        aspects[name] = [defaultValue];
        added.push(name);
      }
    }

    if (added.length === 0) {
      console.log('[ebay-fix-draft-aspects] No aspects needed for SKU:', sku);
      return jsonResponse(200, { ok: true, message: 'No aspects needed to be added', added: [] }, originHdr, METHODS);
    }

    console.log('[ebay-fix-draft-aspects] Adding aspects:', added, 'to SKU:', sku);
    // Update inventory with fixed aspects
    await putInventoryItem(
      access_token,
      apiHost,
      sku,
      {
        condition: inventory.condition,
        product: {
          title: inventory.product.title,
          description: inventory.product.description,
          imageUrls: inventory.product.imageUrls || [],
          aspects,
        },
      },
      inventory.availability?.shipToLocationAvailability?.quantity || 1,
      offer.marketplaceId
    );

    console.log('[ebay-fix-draft-aspects] Successfully added aspects:', added);
    return jsonResponse(200, {
      ok: true,
      message: `Added ${added.length} missing aspects`,
      added,
      sku,
      offerId,
    }, originHdr, METHODS);

  } catch (e: any) {
    console.error('[ebay-fix-draft-aspects] Error:', e);
    return jsonResponse(500, {
      error: 'Failed to fix aspects',
      detail: e?.message || String(e),
    }, originHdr, METHODS);
  }
};

import type { Handler } from '../../src/types/api-handler.js';
import { accessTokenFromRefresh, tokenHosts } from '../../src/lib/_common.js';
import { tokensStore } from '../../src/lib/redis-store.js';
import { getBearerToken, getJwtSubUnverified, requireAuthVerified, userScopedKey } from '../../src/lib/_auth.js';

export const handler: Handler = async (event) => {
  console.log('[ebay-fix-invalid-skus] Function invoked');
  
  try {
    const devBypassEnabled = process.env.DEV_BYPASS_AUTH_FOR_FIX_SKUS === 'true';
    const wantBypass =
      devBypassEnabled &&
      ((event.queryStringParameters?.dev || '').toString() === '1' ||
        (event.headers['x-dev-bypass'] || event.headers['X-Dev-Bypass'] || '').toString() === '1');

    let bearer = getBearerToken(event);
    let sub = (await requireAuthVerified(event))?.sub || null;
    if (!sub) sub = getJwtSubUnverified(event);

    if (wantBypass) {
      sub = event.queryStringParameters?.userId || process.env.DEV_USER_ID || 'dev-user';
      bearer = bearer || 'dev-bypass';
    }

    console.log('[ebay-fix-invalid-skus] User ID:', sub, 'Dev bypass:', wantBypass);

    if (!bearer || !sub) {
      return {
        statusCode: 401,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ error: 'Unauthorized' }),
      };
    }

    // Load refresh token
    const store = tokensStore();
    const saved = (await store.get(userScopedKey(sub, 'ebay.json'), { type: 'json' })) as any;
    const refresh = saved?.refresh_token as string | undefined;
    if (!refresh) {
      console.log('[ebay-fix-invalid-skus] No eBay refresh token found');
      return { statusCode: 400, body: JSON.stringify({ error: 'Connect eBay first' }) };
    }

    console.log('[ebay-fix-invalid-skus] Getting access token...');
    const { access_token } = await accessTokenFromRefresh(refresh);
    const { apiHost } = tokenHosts(process.env.EBAY_ENV);
    const MARKETPLACE_ID = process.env.EBAY_MARKETPLACE_ID || 'EBAY_US';

    // Validate SKU format
    function isValidSKU(sku: string): boolean {
      if (!sku || typeof sku !== 'string') return false;
      if (sku.length > 50) return false;
      return /^[a-zA-Z0-9]+$/.test(sku);
    }

    // Generate a valid SKU from an invalid one
    function fixSKU(invalidSku: string): string {
      // Remove all non-alphanumeric characters
      let fixed = invalidSku.replace(/[^a-zA-Z0-9]/g, '');
      // If empty after cleanup, generate a random one
      if (!fixed) {
        fixed = 'FIXED' + Date.now() + Math.random().toString(36).substring(2, 8);
      }
      // Truncate to 50 chars
      if (fixed.length > 50) {
        fixed = fixed.substring(0, 50);
      }
      return fixed;
    }

    // Fetch all inventory items
    async function fetchAllInventoryItems() {
      const items: any[] = [];
      let offset = 0;
      const limit = 100;

      console.log('[ebay-fix-invalid-skus] Fetching inventory items...');

      while (true) {
        const params = new URLSearchParams({ 
          limit: String(limit), 
          offset: String(offset)
        });
        const url = `${apiHost}/sell/inventory/v1/inventory_item?${params.toString()}`;
        
        const res = await fetch(url, {
          headers: {
            Authorization: `Bearer ${access_token}`,
            'Content-Type': 'application/json',
            'X-EBAY-C-MARKETPLACE-ID': MARKETPLACE_ID,
          },
        });

        if (!res.ok) {
          const text = await res.text();
          console.error(`[ebay-fix-invalid-skus] API error at offset ${offset}:`, res.status, text);
          break;
        }

        const data = await res.json();
        const inventoryItems = Array.isArray(data.inventoryItems) ? data.inventoryItems : [];
        
        console.log(`[ebay-fix-invalid-skus] Offset ${offset}: Found ${inventoryItems.length} items`);
        items.push(...inventoryItems);

        if (!data.next || inventoryItems.length < limit) break;
        offset += limit;
      }

      return items;
    }

    // Get offer for a SKU
    async function getOfferForSKU(sku: string) {
      const params = new URLSearchParams({ sku, limit: '1' });
      const url = `${apiHost}/sell/inventory/v1/offer?${params.toString()}`;
      
      const res = await fetch(url, {
        headers: {
          Authorization: `Bearer ${access_token}`,
          'Content-Type': 'application/json',
          'X-EBAY-C-MARKETPLACE-ID': MARKETPLACE_ID,
        },
      });

      if (!res.ok) return null;
      const data = await res.json();
      return data.offers?.[0] || null;
    }

    // Create new inventory item with valid SKU
    async function createInventoryItem(newSku: string, itemData: any) {
      const url = `${apiHost}/sell/inventory/v1/inventory_item/${encodeURIComponent(newSku)}`;
      
      const res = await fetch(url, {
        method: 'PUT',
        headers: {
          Authorization: `Bearer ${access_token}`,
          'Content-Type': 'application/json',
          'X-EBAY-C-MARKETPLACE-ID': MARKETPLACE_ID,
        },
        body: JSON.stringify(itemData),
      });

      return res.status === 200 || res.status === 201 || res.status === 204;
    }

    // Update offer to use new SKU
    async function updateOfferSKU(offerId: string, newSku: string, offerData: any) {
      const url = `${apiHost}/sell/inventory/v1/offer/${offerId}`;
      
      // Update the offer data with new SKU
      const updatedOffer = { ...offerData, sku: newSku };
      delete updatedOffer.offerId;
      delete updatedOffer.status;
      delete updatedOffer.listing;
      
      const res = await fetch(url, {
        method: 'PUT',
        headers: {
          Authorization: `Bearer ${access_token}`,
          'Content-Type': 'application/json',
          'X-EBAY-C-MARKETPLACE-ID': MARKETPLACE_ID,
        },
        body: JSON.stringify(updatedOffer),
      });

      return res.status === 200 || res.status === 204;
    }

    // Delete old inventory item
    async function deleteInventoryItem(sku: string) {
      const url = `${apiHost}/sell/inventory/v1/inventory_item/${encodeURIComponent(sku)}`;
      
      const res = await fetch(url, {
        method: 'DELETE',
        headers: {
          Authorization: `Bearer ${access_token}`,
          'X-EBAY-C-MARKETPLACE-ID': MARKETPLACE_ID,
        },
      });

      return res.status === 204 || res.status === 200;
    }

    // Main logic
    const allItems = await fetchAllInventoryItems();
    console.log(`[ebay-fix-invalid-skus] Total inventory items: ${allItems.length}`);

    const invalidItems = allItems.filter(item => !isValidSKU(item.sku));
    console.log(`[ebay-fix-invalid-skus] Found ${invalidItems.length} items with invalid SKUs`);

    if (invalidItems.length === 0) {
      return {
        statusCode: 200,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ ok: true, message: 'No invalid SKUs found', fixed: 0 }),
      };
    }

    const results = [];
    let fixed = 0;
    let failed = 0;

    for (const item of invalidItems) {
      const oldSku = item.sku;
      const newSku = fixSKU(oldSku);
      
      console.log(`[ebay-fix-invalid-skus] Fixing "${oldSku}" -> "${newSku}"`);

      try {
        // Get the offer for this SKU
        const offer = await getOfferForSKU(oldSku);
        
        // Create new inventory item with valid SKU
        const itemPayload = { ...item };
        delete itemPayload.sku;
        
        const created = await createInventoryItem(newSku, itemPayload);
        if (!created) {
          console.error(`[ebay-fix-invalid-skus] Failed to create inventory for ${newSku}`);
          failed++;
          results.push({ oldSku, newSku, success: false, reason: 'Failed to create inventory' });
          continue;
        }

        // If there's an offer, update it to use the new SKU
        if (offer) {
          const updated = await updateOfferSKU(offer.offerId, newSku, offer);
          if (!updated) {
            console.error(`[ebay-fix-invalid-skus] Failed to update offer for ${newSku}`);
            failed++;
            results.push({ oldSku, newSku, success: false, reason: 'Failed to update offer' });
            continue;
          }
        }

        // Delete old inventory item
        await deleteInventoryItem(oldSku);

        fixed++;
        results.push({ oldSku, newSku, success: true, hadOffer: !!offer });
        console.log(`[ebay-fix-invalid-skus] ✓ Fixed ${oldSku} (${fixed}/${invalidItems.length})`);

      } catch (err: any) {
        console.error(`[ebay-fix-invalid-skus] Error fixing ${oldSku}:`, err.message);
        failed++;
        results.push({ oldSku, newSku, success: false, reason: err.message });
      }
    }

    console.log(`[ebay-fix-invalid-skus] Complete! Fixed: ${fixed}, Failed: ${failed}`);

    return {
      statusCode: 200,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        ok: true,
        totalInvalid: invalidItems.length,
        fixed,
        failed,
        results,
      }),
    };

  } catch (e: any) {
    console.error('[ebay-fix-invalid-skus] Error:', e?.message || e);
    console.error('[ebay-fix-invalid-skus] Stack:', e?.stack);
    return {
      statusCode: 500,
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ error: 'Failed to fix invalid SKUs', detail: e?.message || String(e) }),
    };
  }
};

import type { Handler } from '../../src/types/api-handler.js';
import { accessTokenFromRefresh, tokenHosts } from '../../src/lib/_common.js';
import { tokensStore } from '../../src/lib/redis-store.js';
import { getBearerToken, getJwtSubUnverified, requireAuthVerified, userScopedKey } from '../../src/lib/_auth.js';

type CleanupItem = { sku: string; excludeOfferId?: string };

export const handler: Handler = async (event) => {
	try {
		// Auth check
		const bearer = getBearerToken(event);
		let sub = (await requireAuthVerified(event))?.sub || null;
		if (!sub) sub = getJwtSubUnverified(event);
		if (!bearer || !sub) {
			return {
				statusCode: 401,
				headers: { 'Content-Type': 'application/json' },
				body: JSON.stringify({ error: 'Unauthorized' }),
			};
		}

		const method = (event.httpMethod || 'GET').toUpperCase();
		let items: CleanupItem[] = [];
		if (method === 'POST' || method === 'PUT') {
			const body = event.body ? JSON.parse(event.body) : {};
			if (Array.isArray(body?.items)) items = body.items as CleanupItem[];
			else if (body?.sku) items = [{ sku: String(body.sku), excludeOfferId: body.excludeOfferId }];
		}
		if (!items.length) {
			const sku = event.queryStringParameters?.sku || '';
			const excludeOfferId = event.queryStringParameters?.excludeOfferId || undefined;
			if (!sku) return { statusCode: 400, body: JSON.stringify({ error: 'missing sku' }) };
			items = [{ sku: String(sku), excludeOfferId }];
		}

		const store = tokensStore();
		const saved = (await store.get(userScopedKey(sub, 'ebay.json'), { type: 'json' })) as any;
		const refresh = saved?.refresh_token as string | undefined;
		if (!refresh) return { statusCode: 400, body: JSON.stringify({ error: 'Connect eBay first' }) };
		const { access_token } = await accessTokenFromRefresh(refresh);
		const { apiHost } = tokenHosts(process.env.EBAY_ENV);
		const MARKETPLACE_ID = process.env.EBAY_MARKETPLACE_ID || 'EBAY_US';
		const headers = {
			Authorization: `Bearer ${access_token}`,
			Accept: 'application/json',
			'Content-Language': 'en-US',
			'Accept-Language': 'en-US',
			'X-EBAY-C-MARKETPLACE-ID': MARKETPLACE_ID,
		} as Record<string, string>;

		async function listOffersBySku(sku: string) {
			const url = `${apiHost}/sell/inventory/v1/offer?sku=${encodeURIComponent(sku)}&limit=200`;
			const r = await fetch(url, { headers });
			const txt = await r.text();
			let json: any; try { json = JSON.parse(txt); } catch { json = { raw: txt }; }
			if (!r.ok) throw Object.assign(new Error('list offers failed'), { status: r.status, body: json, url });
			return Array.isArray(json.offers) ? json.offers : [];
		}
		async function deleteOffer(offerId: string) {
			const url = `${apiHost}/sell/inventory/v1/offer/${encodeURIComponent(offerId)}`;
			const r = await fetch(url, { method: 'DELETE', headers });
			const txt = await r.text();
			let json: any; try { json = JSON.parse(txt); } catch { json = { raw: txt }; }
			return { ok: r.ok, status: r.status, body: json, url };
		}

		const results: any[] = [];
		for (const it of items) {
			const sku = String(it.sku || '').trim();
			if (!sku) { results.push({ sku, error: 'empty sku' }); continue; }
			try {
				const offers = await listOffersBySku(sku);
				const toDelete = offers.filter((o: any) => String(o.status).toUpperCase() === 'UNPUBLISHED' && (!it.excludeOfferId || String(o.offerId) !== String(it.excludeOfferId)));
				const deleted: string[] = []; const errors: any[] = [];
				for (const o of toDelete) {
					const del = await deleteOffer(String(o.offerId));
					if (del.ok) deleted.push(String(o.offerId)); else errors.push({ offerId: String(o.offerId), status: del.status, body: del.body });
				}
				results.push({ sku, count: toDelete.length, deleted, errors });
			} catch (e: any) {
				results.push({ sku, error: e?.body || e?.message || String(e) });
			}
		}
		return { statusCode: 200, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ ok: true, results }) };
	} catch (e: any) {
		return { statusCode: 500, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ error: 'clean-drafts error', detail: e?.message || String(e) }) };
	}
};

import type { Handler } from '../../src/types/api-handler.js';
import { accessTokenFromRefresh, tokenHosts } from '../../src/lib/_common.js';
import { tokensStore } from '../../src/lib/redis-store.js';
import { getBearerToken, getJwtSubUnverified, requireAuthVerified, userScopedKey } from '../../src/lib/_auth.js';

type J = Record<string, any>;

export const handler: Handler = async (event) => {
	const startTime = Date.now();
	const MAX_EXECUTION_TIME = 20000; // 20 seconds (leave buffer before Netlify timeout)
	
	try {
	const qp = event.queryStringParameters || ({} as any);
	const dryRun = /^1|true|yes$/i.test(String(qp.dryRun || qp.dry || 'false'));
	const deleteAllUnpublished = /^1|true|yes$/i.test(String(qp.deleteAll || qp.all || 'false'));
	const deleteInventory = /^1|true|yes$/i.test(String(qp.deleteInventory || qp.inv || 'false'));
	const skipFastScan = /^1|true|yes$/i.test(String(qp.skipFastScan || 'false'));
	const nuclearMode = /^1|true|yes$/i.test(String(qp.nuclear || 'false')); // FAST: Just delete inventory, no offer checking
	const deleteOrphans = /^1|true|yes$/i.test(String(qp.orphans || 'false')); // Delete inventory items with no offers
	
	// Check for admin token bypass
	const isAdminAuth = qp.adminToken && qp.adminToken === process.env.ADMIN_API_TOKEN;
		
		// Get user-scoped eBay token
		const store = tokensStore();
		let sub: string | null = null;
		let refresh: string | undefined;

		if (isAdminAuth) {
			// Admin mode: use userSub parameter to specify which user's token
			const targetUserSub = qp.userSub;
			if (!targetUserSub) {
				return { statusCode: 400, body: JSON.stringify({ error: 'Admin mode requires userSub parameter' }) };
			}
			const saved = (await store.get(userScopedKey(targetUserSub, 'ebay.json'), { type: 'json' })) as J | null;
			refresh = saved?.refresh_token as string | undefined;
			if (!refresh) {
				return { statusCode: 400, body: JSON.stringify({ error: `No eBay token found for user ${targetUserSub}` }) };
			}
			sub = targetUserSub;
		} else {
			// Normal user auth mode
			const bearer = getBearerToken(event);
			sub = (await requireAuthVerified(event))?.sub || null;
			if (!sub) sub = getJwtSubUnverified(event);
			if (!bearer || !sub) return { statusCode: 401, body: JSON.stringify({ error: 'Unauthorized' }) };
			
			const saved = (await store.get(userScopedKey(sub, 'ebay.json'), { type: 'json' })) as J | null;
			refresh = saved?.refresh_token as string | undefined;
			if (!refresh) return { statusCode: 400, body: JSON.stringify({ error: 'Connect eBay first' }) };
		}
		
		const { access_token } = await accessTokenFromRefresh(refresh);

		const ENV = process.env.EBAY_ENV || 'PROD';
		const { apiHost } = tokenHosts(ENV);
		const MARKETPLACE_ID = process.env.EBAY_MARKETPLACE_ID || 'EBAY_US';
		const headers = {
			Authorization: `Bearer ${access_token}`,
			Accept: 'application/json',
			'Content-Language': 'en-US',
			'Accept-Language': 'en-US',
			'X-EBAY-C-MARKETPLACE-ID': MARKETPLACE_ID,
			'Content-Type': 'application/json',
		} as Record<string, string>;

		const results = {
			mode: { dryRun, deleteAllUnpublished, deleteInventory },
			deletedOffers: [] as any[],
			deletedInventory: [] as any[],
			errors: [] as any[],
			attempts: [] as any[],
		};

		const validSku = (s?: string) => !!s && /^[A-Za-z0-9]{1,50}$/.test(s);

		async function listInventory(offset = 0) {
			const params = new URLSearchParams({ limit: '200', offset: String(offset) });
			const url = `${apiHost}/sell/inventory/v1/inventory_item?${params.toString()}`;
			const r = await fetch(url, { headers });
			const t = await r.text();
			let j: any;
			try {
				j = JSON.parse(t);
			} catch {
				j = { raw: t };
			}
			results.attempts.push({ status: r.status, url, body: j });
			if (!r.ok) throw new Error(`inventory list failed ${r.status}`);
			const items = Array.isArray(j?.inventoryItems) ? j.inventoryItems : [];
			return { items, next: j?.href && j?.next ? j.next : null };
		}

		async function deleteOffer(offerId: string) {
			const url = `${apiHost}/sell/inventory/v1/offer/${encodeURIComponent(offerId)}`;
			if (dryRun) {
				results.deletedOffers.push({ offerId, dryRun: true });
				return true;
			}
			const r = await fetch(url, { method: 'DELETE', headers });
			if (r.ok) {
				results.deletedOffers.push({ offerId });
				return true;
			}
			const t = await r.text();
			let j: any;
			try {
				j = JSON.parse(t);
			} catch {
				j = { raw: t };
			}
			results.errors.push({ action: 'delete-offer', offerId, url, status: r.status, body: j });
			return false;
		}

		async function deleteInventoryItem(sku: string, forceAllowDeletion = false) {
			const url = `${apiHost}/sell/inventory/v1/inventory_item/${encodeURIComponent(sku)}`;
			if (!deleteInventory && !forceAllowDeletion) return false;
			if (dryRun) {
				results.deletedInventory.push({ sku, dryRun: true });
				return true;
			}
			const r = await fetch(url, { method: 'DELETE', headers });
			if (r.ok) {
				results.deletedInventory.push({ sku });
				return true;
			}
			const t = await r.text();
			let j: any;
			try {
				j = JSON.parse(t);
			} catch {
				j = { raw: t };
			}
			results.errors.push({ action: 'delete-inventory', sku, url, status: r.status, body: j });
			return false;
		}

		async function listOffersForSku(sku: string): Promise<any[]> {
			if (!validSku(sku)) return [];
			const params = new URLSearchParams({ sku, limit: '50' });
			const url = `${apiHost}/sell/inventory/v1/offer?${params.toString()}`;
			const r = await fetch(url, { headers });
			if (!r.ok) return [];
			const t = await r.text();
			let j: any;
			try {
				j = JSON.parse(t);
			} catch {
				return [];
			}
			results.attempts.push({ status: r.status, url, body: j });
			return Array.isArray(j?.offers) ? j.offers : [];
		}
		
		async function listAllOffersDirect(offset = 0): Promise<{ offers: any[]; next: string | null }> {
			// Direct offers listing - faster than scanning inventory
			const params = new URLSearchParams({ limit: '100', offset: String(offset) });
			const url = `${apiHost}/sell/inventory/v1/offer?${params.toString()}`;
			const r = await fetch(url, { headers });
			if (!r.ok) {
				const t = await r.text();
				let j: any;
				try { j = JSON.parse(t); } catch { j = { raw: t }; }
			results.attempts.push({ status: r.status, url, body: j });
			// Error 25707 means invalid SKU in listing - throw to trigger fast scan
			if (r.status === 400 && j?.errors?.[0]?.errorId === 25707) {
				console.warn('[clean-broken-drafts] Invalid SKU in offers list (25707), stopping direct listing');
				throw new Error('Error 25707: Invalid SKU in offers');
			}
			throw new Error(`offers list failed ${r.status}`);
			}
			const t = await r.text();
			let j: any;
			try { j = JSON.parse(t); } catch { j = { raw: t }; }
			results.attempts.push({ status: r.status, url, body: j });
			const offers = Array.isArray(j?.offers) ? j.offers : [];
			return { offers, next: j?.href && j?.next ? j.next : null };
		}

	// Declare timeout vars BEFORE fast path to avoid TDZ errors
	let timedOut = false;
	const INTERNAL_LIMIT = 20000; // 20-second upper bound to avoid Netlify hard timeout
	
	// NUCLEAR MODE: Just delete all inventory items directly (fastest, no offer checking)
	if (nuclearMode && deleteInventory) {
		console.log('[clean-broken-drafts] NUCLEAR MODE: Deleting all inventory items directly (no offer checks)');
		let invOffset = 0;
		let scanned = 0;
		
		while (scanned < 2000) {
			if (Date.now() - startTime > INTERNAL_LIMIT) {
				console.log(`[clean-broken-drafts] Nuclear mode timeout at ${scanned} items (20s limit)`);
				timedOut = true;
				break;
			}
			
			const page = await listInventory(invOffset);
			const items = page.items;
			if (!items.length) break;
			
			console.log(`[clean-broken-drafts] Nuclear batch: offset=${invOffset}, count=${items.length}`);
			
			for (const it of items) {
				const sku = it?.sku;
				if (!sku) continue;
				
				scanned++;
				try {
					await deleteInventoryItem(sku);
					results.deletedInventory.push({ sku });
				} catch (err) {
					results.errors.push({ sku, error: String(err) });
				}
			}
			
			if (!page.next) break;
			invOffset += 200;
		}
		
		return {
			statusCode: 200,
			headers: { 'Content-Type': 'application/json' },
			body: JSON.stringify({
				ok: true,
				mode: { ...results.mode, nuclear: true },
				nuclearMode: true,
				scanned,
				timedOut,
				deletedInventory: results.deletedInventory,
				errors: results.errors,
				message: timedOut ? 'Partial deletion - run again' : `Deleted ${results.deletedInventory.length} items`
			}),
