import type { Handler } from '../../src/types/api-handler.js';
import { requireAuth, json } from '../../src/lib/_auth.js';
import { getUserAccessToken, apiHost, headers } from '../../src/lib/_ebay.js';

export const handler: Handler = async (event) => {
	try {
		const auth = await requireAuth(event);
		if (!auth) return json({ error: 'unauthorized' }, 401);
		const body = event.body ? JSON.parse(event.body) : {};
		const type = String(body.type || '').toLowerCase();
		const id = String(body.id || '').trim();
		if (!type || !id) return json({ error: 'missing type or id' }, 400);

		let token: string;
		try { token = await getUserAccessToken(auth.sub); } catch (e: any) {
			if (e?.code === 'ebay-not-connected') return json({ error: 'ebay-not-connected' }, 400);
			return json({ error: 'token-mint-failed', detail: e?.message || String(e) }, 500);
		}
		const host = apiHost();
		const h = headers(token);
		const mp = h['X-EBAY-C-MARKETPLACE-ID'] || 'EBAY_US';

		const map: Record<string, string> = {
			payment: 'payment_policy',
			fulfillment: 'fulfillment_policy',
			shipping: 'fulfillment_policy',
			return: 'return_policy',
			returns: 'return_policy',
		};
		const path = map[type];
		if (!path) return json({ error: 'invalid type' }, 400);
		const url = `${host}/sell/account/v1/${path}/${encodeURIComponent(id)}`;

		// Fetch current policy to merge safely
		const curRes = await fetch(url, { headers: h });
		const curTxt = await curRes.text(); let cur: any; try { cur = JSON.parse(curTxt); } catch { cur = {}; }
		if (!curRes.ok) return json({ error: 'get-policy failed', status: curRes.status, detail: cur }, curRes.status);

		// Helper: normalize categoryTypes without deprecated 'default' flag
		const normalizeCategoryTypes = (ct: any): any[] => {
			const arr: any[] = Array.isArray(ct) && ct.length ? ct : [{ name: 'ALL_EXCLUDING_MOTORS_VEHICLES' }];
			return arr.map((x) => ({ name: x?.name || 'ALL_EXCLUDING_MOTORS_VEHICLES', default: true }));
		};

		const stripReadOnly = (obj: any, keys: string[]) => {
			for (const k of keys) delete obj[k];
			return obj;
		};

		const ensureFulfillmentShippingOptions = (
			curOptions: any,
			forceFreeDomestic: boolean,
			selectedCostType?: 'CALCULATED' | 'FLAT_RATE',
			carrier?: string,
			serviceCode?: string,
			shippingCostValue?: string,
			additionalShippingCostValue?: string
		) => {
			const baseShipTo = { regionIncluded: [{ regionType: 'COUNTRY', regionName: 'US' }] };
			const normalizeMoney = (money: any, fallback = '0.00') => {
				if (!money || typeof money !== 'object') return { value: fallback, currency: 'USD' };
				const currency = money.currency || 'USD';
				const raw = money.value;
				if (typeof raw === 'string') return { value: raw, currency };
				const num = Number(raw);
				return { value: Number.isFinite(num) ? num.toFixed(2) : fallback, currency };
			};
			const normalizeServices = (services: any[]) =>
				Array.isArray(services)
					? services.map((svc, idx) => {
							const next = { ...svc };
							if (next.sortOrder == null) {
								const parsed = Number(next.sortOrderId);
								next.sortOrder = Number.isFinite(parsed) ? parsed : idx + 1;
							}
							delete next.sortOrderId;
							if (next.shippingCost) next.shippingCost = normalizeMoney(next.shippingCost);
							if (next.additionalShippingCost)
								next.additionalShippingCost = normalizeMoney(next.additionalShippingCost);
							next.buyerResponsibleForShipping = !!next.buyerResponsibleForShipping;
							next.buyerResponsibleForPickup = !!next.buyerResponsibleForPickup;
							return next;
						})
					: services;

			const wrapOption = (partial: any) => {
				const next = {
					optionType: 'DOMESTIC',
					shipToLocations: baseShipTo,
					packageHandlingCost: { value: '0.00', currency: 'USD' },
					shippingDiscountProfileId: '0',
					shippingPromotionOffered: false,
					...partial,
				};
				delete next.insuranceFee;
				next.shipToLocations = next.shipToLocations || baseShipTo;
				next.packageHandlingCost = normalizeMoney(next.packageHandlingCost);
				next.shippingDiscountProfileId =
					next.shippingDiscountProfileId != null ? String(next.shippingDiscountProfileId) : '0';
				next.shippingPromotionOffered = !!next.shippingPromotionOffered;
				next.shippingServices = normalizeServices(next.shippingServices);
				return next;
			};

			if (forceFreeDomestic) {
				return [
					wrapOption({
						costType: 'FLAT_RATE',
						shippingServices: [
							{
								shippingServiceCode: 'USPSParcel',
								sortOrder: 1,
								freeShipping: true,
								shippingCarrierCode: 'USPS',
							},
						],
					}),
				];
			}

			if (serviceCode) {
				const shipCarrier = carrier || 'USPS';
				return [
					wrapOption({
						costType: selectedCostType || 'CALCULATED',
						shippingServices: [
							{
								shippingServiceCode: serviceCode,
								freeShipping: false,
								sortOrder: 1,
								...(selectedCostType === 'FLAT_RATE'
									? { shippingCost: { value: shippingCostValue || '0.00', currency: 'USD' } }
									: {}),
								...(additionalShippingCostValue
									? { additionalShippingCost: { value: additionalShippingCostValue, currency: 'USD' } }
									: {}),
								shippingCarrierCode: shipCarrier,
							},
						],
					}),
				];
			}

			if (Array.isArray(curOptions) && curOptions.length) {
				return curOptions.map((opt: any) => wrapOption({ ...opt }));
			}

			return [
				wrapOption({
					costType: selectedCostType || 'CALCULATED',
					shippingServices: [
						{
							shippingServiceCode: 'USPSParcel',
							freeShipping: false,
							sortOrder: 1,
							...(selectedCostType === 'FLAT_RATE'
								? { shippingCost: { value: shippingCostValue || '0.00', currency: 'USD' } }
								: {}),
							shippingCarrierCode: 'USPS',
						},
					],
				}),
			];
		};

		let payload: any = {};
		if (path === 'payment_policy') {
			// Start from current and override selected fields
			payload = {
				...cur,
				name: body.name ?? cur.name,
				marketplaceId: mp,
				categoryTypes: normalizeCategoryTypes(cur.categoryTypes),
				immediatePay: body.immediatePay ?? cur.immediatePay ?? false,
			};
			stripReadOnly(payload, [
				'paymentPolicyId',
				'policyId',
				'creationDate',
				'lastModifiedDate',
				'@odata.etag',
				'warnings',
			]);
		} else if (path === 'fulfillment_policy') {
			const handlingDays = Number(body.handlingTimeDays ?? cur?.handlingTime?.value ?? 1);
			const shippingOptions = ensureFulfillmentShippingOptions(
				cur.shippingOptions,
				body.freeDomestic === true,
				(body.costType as any) || undefined,
				body.shippingCarrierCode,
				body.shippingServiceCode,
				body.shippingCostValue,
				body.additionalShippingCostValue
			);
			const globalShipping =
				body.globalShipping != null ? !!body.globalShipping : !!cur.globalShipping;
			const pickupDropOff =
				body.pickupDropOff != null ? !!body.pickupDropOff : !!cur.pickupDropOff;
			const freightShipping =
				body.freightShipping != null ? !!body.freightShipping : !!cur.freightShipping;
			// Build a minimal, valid payload to avoid sending read-only/unsupported fields
			payload = {
				name: body.name ?? cur.name,
				marketplaceId: mp,
				categoryTypes: normalizeCategoryTypes(cur.categoryTypes),
				handlingTime: { value: Math.max(0, handlingDays), unit: 'DAY' },
				shippingOptions,
				shipToLocations: { regionIncluded: [{ regionType: 'COUNTRY', regionName: 'US' }] },
				globalShipping,
				pickupDropOff,
				freightShipping,
			};
			stripReadOnly(payload, [
				'fulfillmentPolicyId',
				'policyId',
				'creationDate',
				'lastModifiedDate',
				'@odata.etag',
				'warnings',
			]);
		} else if (path === 'return_policy') {
			const returnsAccepted = body.returnsAccepted ?? cur.returnsAccepted ?? true;
			const periodDays = Number(body.returnPeriodDays ?? cur?.returnPeriod?.value ?? 30);
			payload = returnsAccepted
				? {
						name: body.name ?? cur.name,
						marketplaceId: mp,
						returnsAccepted: true,
						returnPeriod: { value: Math.max(1, periodDays), unit: 'DAY' },
						returnShippingCostPayer:
							body.returnShippingCostPayer ?? cur.returnShippingCostPayer ?? 'BUYER',
						refundMethod: body.refundMethod ?? cur.refundMethod ?? 'MONEY_BACK',
					}
				: {
						name: body.name ?? cur.name,
						marketplaceId: mp,
						returnsAccepted: false,
					};
			stripReadOnly(payload, [
				'returnPolicyId',
				'policyId',
				'creationDate',
				'lastModifiedDate',
				'@odata.etag',
				'warnings',
			]);
		}

		const putRes = await fetch(url, { method: 'PUT', headers: h, body: JSON.stringify(payload) });
		const putTxt = await putRes.text(); let putBody: any; try { putBody = JSON.parse(putTxt); } catch { putBody = { raw: putTxt }; }
		if (!putRes.ok) return json({ error: 'update-policy failed', status: putRes.status, detail: putBody }, putRes.status);
		return json({ ok: true, policy: putBody });
	} catch (e: any) {
		return json({ error: e?.message || String(e) }, 500);
	}
};

import type { Handler } from '../../src/types/api-handler.js';
import { requireAuth, json } from '../../src/lib/_auth.js';
import { getUserAccessToken, apiHost, headers } from '../../src/lib/_ebay.js';

export const handler: Handler = async (event) => {
	try {
		const auth = await requireAuth(event);
		if (!auth) return json({ error: 'unauthorized' }, 401);

		let token: string;
		try {
			token = await getUserAccessToken(auth.sub);
		} catch (e: any) {
			if (e?.code === 'ebay-not-connected') return json({ error: 'ebay-not-connected' }, 400);
			return json({ error: 'token-mint-failed', detail: e?.message || String(e) }, 500);
		}

		const host = apiHost();
		const h = headers(token);
		const mp = h['X-EBAY-C-MARKETPLACE-ID'] || 'EBAY_US';

		async function getJson(url: string) {
			const r = await fetch(url, { headers: h });
			const t = await r.text();
			let j: any;
			try {
				j = JSON.parse(t);
			} catch {
				j = { raw: t };
			}
			return { ok: r.ok, status: r.status, body: j };
		}

		async function postJson(url: string, body: any) {
			const r = await fetch(url, { method: 'POST', headers: h, body: JSON.stringify(body) });
			const t = await r.text();
			let j: any;
			try {
				j = JSON.parse(t);
			} catch {
				j = { raw: t };
			}
			return { ok: r.ok, status: r.status, body: j };
		}

		const pay = await getJson(`${host}/sell/account/v1/payment_policy?marketplace_id=${mp}`);
		const ful = await getJson(`${host}/sell/account/v1/fulfillment_policy?marketplace_id=${mp}`);
		const ret = await getJson(`${host}/sell/account/v1/return_policy?marketplace_id=${mp}`);

		const paymentPolicies = Array.isArray(pay.body?.paymentPolicies) ? pay.body.paymentPolicies : [];
		const fulfillmentPolicies = Array.isArray(ful.body?.fulfillmentPolicies) ? ful.body.fulfillmentPolicies : [];
		const returnPolicies = Array.isArray(ret.body?.returnPolicies) ? ret.body.returnPolicies : [];

		const result: { paymentPolicyId?: string; fulfillmentPolicyId?: string; returnPolicyId?: string } = {};

		let payPick = paymentPolicies[0];
		const payDefaultName = 'Default Payment (Auto)';
		const namedPay = paymentPolicies.find((p: any) => (p?.name || '') === payDefaultName);
		if (namedPay) payPick = namedPay;
		if (!payPick) {
			const payload = {
				name: payDefaultName,
				marketplaceId: mp,
				categoryTypes: [{ name: 'ALL_EXCLUDING_MOTORS_VEHICLES' }],
				immediatePay: true,
			};
			const created = await postJson(`${host}/sell/account/v1/payment_policy`, payload);
			if (!created.ok) {
				return json({ ok: false, error: 'payment-create-failed', detail: created.body }, created.status);
			}
			payPick = created.body;
		}
		result.paymentPolicyId = String(payPick?.id || payPick?.paymentPolicyId || payPick?.policyId || '');

		let fulPick = fulfillmentPolicies[0];
		const fulDefaultName = 'Default Shipping (Auto)';
		const namedFul = fulfillmentPolicies.find((p: any) => (p?.name || '') === fulDefaultName);
		if (namedFul) fulPick = namedFul;
		if (!fulPick) {
			const payload = {
				name: fulDefaultName,
				marketplaceId: mp,
				categoryTypes: [{ name: 'ALL_EXCLUDING_MOTORS_VEHICLES', default: true }],
				handlingTime: { value: 1, unit: 'DAY' },
				shippingOptions: [
					{
						optionType: 'DOMESTIC',
						costType: 'FLAT_RATE',
						shippingServices: [
							{
								freeShipping: true,
								shippingCarrierCode: 'USPS',
								shippingServiceCode: 'USPSPriorityFlatRateBox',
								sortOrder: 1,
								buyerResponsibleForShipping: false,
								buyerResponsibleForPickup: false,
							},
						],
						packageHandlingCost: { value: '0.00', currency: 'USD' },
						shippingDiscountProfileId: '0',
						shippingPromotionOffered: false,
						shipToLocations: { regionIncluded: [{ regionType: 'COUNTRY', regionName: 'US' }] },
					},
				],
				shipToLocations: { regionIncluded: [{ regionType: 'COUNTRY', regionName: 'US' }] },
				globalShipping: false,
				pickupDropOff: false,
				freightShipping: false,
			};
			const created = await postJson(`${host}/sell/account/v1/fulfillment_policy`, payload);
			if (!created.ok) {
				return json({ ok: false, error: 'fulfillment-create-failed', detail: created.body }, created.status);
			}
			fulPick = created.body;
		}
		result.fulfillmentPolicyId = String(fulPick?.id || fulPick?.fulfillmentPolicyId || fulPick?.policyId || '');

		let retPick = returnPolicies[0];
		const retDefaultName = 'Default Returns (Auto)';
		const namedRet = returnPolicies.find((p: any) => (p?.name || '') === retDefaultName);
		if (namedRet) retPick = namedRet;
		if (!retPick) {
			const payload = {
				name: retDefaultName,
				marketplaceId: mp,
				returnsAccepted: true,
				returnPeriod: { value: 30, unit: 'DAY' },
				returnShippingCostPayer: 'BUYER',
				refundMethod: 'MONEY_BACK',
			};
			const created = await postJson(`${host}/sell/account/v1/return_policy`, payload);
			retPick = created.body;
		}
		result.returnPolicyId = String(retPick?.id || retPick?.returnPolicyId || retPick?.policyId || '');

		return json({ ok: true, ...result });
	} catch (e: any) {
		return json({ error: e?.message || String(e) }, 500);
	}
};

import type { Handler } from '../../src/types/api-handler.js';
import { tokensStore } from '../../src/lib/redis-store.js';
import { getBearerToken, getJwtSubUnverified, requireAuthVerified, userScopedKey } from '../../src/lib/_auth.js';
import { accessTokenFromRefresh, tokenHosts } from '../../src/lib/_common.js';

type JsonRes = { status: number; json: any };

export const handler: Handler = async (event) => {
	try {
		const store = tokensStore();
		const bearer = getBearerToken(event);
		let sub = (await requireAuthVerified(event))?.sub || null;
		if (!sub) sub = getJwtSubUnverified(event);
		if (!bearer || !sub)
			return {
				statusCode: 401,
				headers: { 'Content-Type': 'application/json' },
				body: JSON.stringify({ error: 'Unauthorized' }),
			};
		const saved = (await store.get(userScopedKey(sub, 'ebay.json'), { type: 'json' })) as any;
		const refresh = saved?.refresh_token as string | undefined;
		if (!refresh)
			return {
				statusCode: 400,
				headers: { 'Content-Type': 'application/json' },
				body: JSON.stringify({ error: 'Connect eBay first' }),
			};

		const { access_token } = await accessTokenFromRefresh(refresh);
		const { apiHost } = tokenHosts(process.env.EBAY_ENV);
		const MARKETPLACE_ID = process.env.EBAY_MARKETPLACE_ID || 'EBAY_US';

		const headers = {
			Authorization: `Bearer ${access_token}`,
			'Content-Type': 'application/json',
			'Accept-Language': 'en-US',
			'Content-Language': 'en-US',
			'X-EBAY-C-MARKETPLACE-ID': MARKETPLACE_ID,
		} as Record<string, string>;

		async function getJson(path: string): Promise<JsonRes> {
			const res = await fetch(`${apiHost}${path}`, { headers });
			const txt = await res.text();
			try {
				return { status: res.status, json: JSON.parse(txt) };
			} catch {
				return { status: res.status, json: { raw: txt } };
			}
		}

		async function postJson(path: string, body: any): Promise<JsonRes> {
			const res = await fetch(`${apiHost}${path}`, {
				method: 'POST',
				headers,
				body: JSON.stringify(body),
			});
			const txt = await res.text();
			try {
				return { status: res.status, json: JSON.parse(txt) };
			} catch {
				return { status: res.status, json: { raw: txt } };
			}
		}

		// Check eligibility via listing endpoints (will return 20403 if not eligible)
		const [fulfillmentList, paymentList, returnList] = await Promise.all([
			getJson(`/sell/account/v1/fulfillment_policy?marketplace_id=${MARKETPLACE_ID}`),
			getJson(`/sell/account/v1/payment_policy?marketplace_id=${MARKETPLACE_ID}`),
			getJson(`/sell/account/v1/return_policy?marketplace_id=${MARKETPLACE_ID}`),
		]);

		const hasNotEligible = [fulfillmentList, paymentList, returnList].some(
			(r) => Array.isArray(r?.json?.errors) && r.json.errors.some((e: any) => e?.errorId === 20403)
		);
		if (hasNotEligible) {
			return {
				statusCode: 400,
				headers: { 'Content-Type': 'application/json' },
				body: JSON.stringify({
					error: 'not-eligible',
					message: 'This account is not opted into Business Policies.',
					hint: 'Opt in at https://www.ebay.com/sh/str/selling-policies (Account settings > Selling > Business policies), then retry.',
					marketplaceId: MARKETPLACE_ID,
					diagnostics: { fulfillmentList, paymentList, returnList },
				}),
			};
		}

		// If lists returned successfully, extract existing names
		const existing = {
			fulfillment: (fulfillmentList.json?.fulfillmentPolicies || []) as any[],
			payment: (paymentList.json?.paymentPolicies || []) as any[],
			returns: (returnList.json?.returnPolicies || []) as any[],
		};

			const results: Record<string, any> = { marketplaceId: MARKETPLACE_ID };
			const chosen: { fulfillment?: string; payment?: string; return?: string } = {};

		// Create Payment Policy if none by our default name
		const defaultPaymentName = 'Default Payment (Auto)';
		const hasPayment = existing.payment.some((p) => p.name === defaultPaymentName);
		if (!hasPayment) {
			const payload = {
				name: defaultPaymentName,
				marketplaceId: MARKETPLACE_ID,
				categoryTypes: [{ name: 'ALL_EXCLUDING_MOTORS_VEHICLES' }],
				// immediatePay can be toggled later via UI if desired
				immediatePay: false,
			};
			const resp = await postJson('/sell/account/v1/payment_policy', payload);
			results.payment = resp;
			try {
				const id = String(
					resp?.json?.id || resp?.json?.paymentPolicyId || resp?.json?.policyId || ''
				).trim();
				if (id) chosen.payment = id;
			} catch {}
		} else {
			results.payment = { status: 'exists' };
			try {
				const found = existing.payment.find((p) => p.name === defaultPaymentName);
				const id = String(
					found?.id || found?.paymentPolicyId || found?.policyId || ''
				).trim();
				if (id) chosen.payment = id;
			} catch {}
		}

		// Create Return Policy if none by our preferred name
		const qs = event?.queryStringParameters || ({} as Record<string, string>);
		const envReturns = (process.env.EBAY_RETURNS_ACCEPTED || '').toLowerCase();
		const qsReturns = (qs['returnsAccepted'] || qs['returns'] || '').toLowerCase();
		const wantsNoReturns =
			qsReturns === 'false' ||
			qsReturns === 'none' ||
			envReturns === 'false' ||
			envReturns === 'none';
		const returnPolicyName = wantsNoReturns ? 'No Returns (Auto)' : 'Default Returns (Auto)';
		const hasReturn = existing.returns.some((p) => p.name === returnPolicyName);
		if (!hasReturn) {
			const payload = wantsNoReturns
				? {
						name: returnPolicyName,
						marketplaceId: MARKETPLACE_ID,
						returnsAccepted: false,
					}
				: {
						name: returnPolicyName,
						marketplaceId: MARKETPLACE_ID,
						returnsAccepted: true,
						returnPeriod: { value: 30, unit: 'DAY' },
						returnShippingCostPayer: 'BUYER',
						refundMethod: 'MONEY_BACK',
					};
			const resp = await postJson('/sell/account/v1/return_policy', payload);
			results.returns = resp;
			try {
				const id = String(
					resp?.json?.id || resp?.json?.returnPolicyId || resp?.json?.policyId || ''
				).trim();
				if (id) chosen.return = id;
			} catch {}
		} else {
			results.returns = { status: 'exists', name: returnPolicyName };
			try {
				const found = existing.returns.find((p) => p.name === returnPolicyName);
				const id = String(
					found?.id || found?.returnPolicyId || found?.policyId || ''
				).trim();
				if (id) chosen.return = id;
			} catch {}
		}

		// Create Fulfillment Policy if none by our default name
		const defaultShipName = 'Default Shipping (Auto)';
		const hasFulfillment = existing.fulfillment.some((p) => p.name === defaultShipName);
		if (!hasFulfillment) {
			const payload = {
				name: defaultShipName,
				marketplaceId: MARKETPLACE_ID,
				categoryTypes: [{ name: 'ALL_EXCLUDING_MOTORS_VEHICLES', default: true }],
				handlingTime: { value: 1, unit: 'DAY' },
				shippingOptions: [
					{
						optionType: 'DOMESTIC',
						costType: 'FLAT_RATE',
						shippingServices: [
							{
								// Free domestic USPS Priority Flat Rate Box (doc sample, widely accepted)
								freeShipping: true,
								shippingCarrierCode: 'USPS',
								shippingServiceCode: 'USPSPriorityFlatRateBox',
								sortOrder: 1,
								buyerResponsibleForShipping: false,
								buyerResponsibleForPickup: false,
							},
						],
						packageHandlingCost: { value: '0.00', currency: 'USD' },
						shippingDiscountProfileId: '0',
						shippingPromotionOffered: false,
						shipToLocations: { regionIncluded: [{ regionType: 'COUNTRY', regionName: 'US' }] },
					},
				],
				shipToLocations: { regionIncluded: [{ regionType: 'COUNTRY', regionName: 'US' }] },
				globalShipping: false,
				pickupDropOff: false,
				freightShipping: false,
			};
			const resp = await postJson('/sell/account/v1/fulfillment_policy', payload);
			results.fulfillment = resp;
			try {
				const id = String(
					resp?.json?.id || resp?.json?.fulfillmentPolicyId || resp?.json?.policyId || ''
				).trim();
				if (id) chosen.fulfillment = id;
			} catch {}
		} else {
			results.fulfillment = { status: 'exists' };
			try {
				const found = existing.fulfillment.find((p) => p.name === defaultShipName);
				const id = String(
					found?.id || found?.fulfillmentPolicyId || found?.policyId || ''
				).trim();
				if (id) chosen.fulfillment = id;
			} catch {}
		}

		// Persist selected policy IDs as this user's defaults so draft creation uses all three
		try {
			const key = userScopedKey(sub, 'policy-defaults.json');
			const cur = ((await store.get(key, { type: 'json' })) as any) || {};
			const merged = { ...cur, ...chosen };
			// Remove empty values
			Object.keys(merged).forEach((k) => {
				if (!merged[k]) delete merged[k];
			});
			if (Object.keys(merged).length) await store.set(key, JSON.stringify(merged));
			results.defaults = { saved: true, values: merged };
		} catch {
			// ignore
		}

		return {
			statusCode: 200,
			headers: { 'Content-Type': 'application/json' },
			body: JSON.stringify({ ok: true, results }),
		};
	} catch (e: any) {
		return {
			statusCode: 500,
			headers: { 'Content-Type': 'application/json' },
			body: JSON.stringify({ error: e?.message || String(e) }),
		};
	}
};

import type { Handler } from '../../src/types/api-handler.js';
import { tokensStore } from '../../src/lib/redis-store.js';
import { getBearerToken, getJwtSubUnverified, requireAuthVerified, userScopedKey } from '../../src/lib/_auth.js';

export const handler: Handler = async (event) => {
	try {
		const bearer = getBearerToken(event);
		let sub = (await requireAuthVerified(event))?.sub || null;
		if (!sub) sub = getJwtSubUnverified(event);
		if (!bearer || !sub) return { statusCode: 401, body: 'Unauthorized' };

		const body = event.body ? JSON.parse(event.body) : {};
		const fulfillment = body.fulfillment as string | undefined;
		const payment = body.payment as string | undefined;
		const ret = body.return as string | undefined;
		const promoCampaignId = body.promoCampaignId as string | undefined;

		const store = tokensStore();
		const key = userScopedKey(sub, 'policy-defaults.json');
		let prefs: any = {};
		try { 
			prefs = (await store.get(key, { type: 'json' })) as any; 
		} catch (e: any) {
			console.warn(`[ebay-set-policy-defaults] Failed to load existing defaults:`, e?.message);
		}
		if (!prefs || typeof prefs !== 'object') prefs = {};
		if (fulfillment != null) prefs.fulfillment = String(fulfillment || '').trim() || undefined;
		if (payment != null) prefs.payment = String(payment || '').trim() || undefined;
		if (ret != null) prefs.return = String(ret || '').trim() || undefined;
		if (promoCampaignId !== undefined) prefs.promoCampaignId = promoCampaignId ? String(promoCampaignId).trim() : null;
		// Clean undefined keys
		Object.keys(prefs).forEach((k) => { if (prefs[k] == null || prefs[k] === '') delete prefs[k]; });
		await store.set(key, JSON.stringify(prefs));
		console.log(`[ebay-set-policy-defaults] Updated defaults for user ${sub}:`, prefs);
		return { statusCode: 200, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ ok: true, defaults: prefs }) };
	} catch (e: any) {
		return { statusCode: 500, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify({ error: e?.message || String(e) }) };
	}
};

import type { Handler } from '../../src/types/api-handler.js';
import { tokensStore } from '../../src/lib/redis-store.js';
import { getBearerToken, getJwtSubUnverified, requireAuthVerified, userScopedKey } from '../../src/lib/_auth.js';
import { accessTokenFromRefresh, tokenHosts } from '../../src/lib/_common.js';

function normalizeMoney(input: any, fallbackCurrency = 'USD', fallbackValue = '0.00') {
	if (!input || typeof input !== 'object') {
		return { value: fallbackValue, currency: fallbackCurrency };
	}
	const currency = input.currency || fallbackCurrency;
	const rawVal = input.value;
	if (typeof rawVal === 'string') {
		return { value: rawVal, currency };
	}
	const num = Number(rawVal);
	return {
		value: Number.isFinite(num) ? num.toFixed(2) : fallbackValue,
		currency,
	};
}

function sanitizeFulfillmentPayload(payload: any) {
	if (!payload || typeof payload !== 'object') return payload;
	payload.globalShipping = !!payload.globalShipping;
	payload.pickupDropOff = !!payload.pickupDropOff;
	payload.freightShipping = !!payload.freightShipping;
	if (!payload.shipToLocations) payload.shipToLocations = { regionIncluded: [{ regionType: 'COUNTRY', regionName: 'US' }] };
	if (!Array.isArray(payload.shippingOptions)) return payload;

	payload.shippingOptions = payload.shippingOptions.map((option: any, optIdx: number) => {
		if (!option || typeof option !== 'object') return option;
		const normalized = { ...option };
		delete normalized.insuranceFee;
		if (!normalized.shipToLocations) normalized.shipToLocations = { regionIncluded: [{ regionType: 'COUNTRY', regionName: 'US' }] };

		normalized.packageHandlingCost = normalizeMoney(normalized.packageHandlingCost);
		normalized.shippingDiscountProfileId = normalized.shippingDiscountProfileId != null
			? String(normalized.shippingDiscountProfileId)
			: '0';
		normalized.shippingPromotionOffered = !!normalized.shippingPromotionOffered;

		if (Array.isArray(normalized.shippingServices)) {
			normalized.shippingServices = normalized.shippingServices.map((svc: any, svcIdx: number) => {
				if (!svc || typeof svc !== 'object') return svc;
				const service = { ...svc };
				if (service.sortOrder == null) {
					const parsed = Number(service.sortOrderId);
					service.sortOrder = Number.isFinite(parsed) ? parsed : svcIdx + 1;
				}
				delete service.sortOrderId;
				if (service.shippingCost && typeof service.shippingCost.value === 'number') {
					service.shippingCost = {
						...service.shippingCost,
						value: service.shippingCost.value.toFixed(2),
					};
				}
				if (service.additionalShippingCost && typeof service.additionalShippingCost.value === 'number') {
					service.additionalShippingCost = {
						...service.additionalShippingCost,
						value: service.additionalShippingCost.value.toFixed(2),
					};
				}
				service.buyerResponsibleForShipping = !!service.buyerResponsibleForShipping;
				service.buyerResponsibleForPickup = !!service.buyerResponsibleForPickup;
				return service;
			});
		}
		if (!Array.isArray(normalized.shippingServices)) normalized.shippingServices = [];

		if (normalized.calculatedShippingRate) {
			const calc = { ...normalized.calculatedShippingRate };
			const fixDim = (dim: any) => {
				if (!dim || typeof dim !== 'object') return dim;
				const val = dim.value;
				return typeof val === 'string' ? dim : { ...dim, value: val != null ? String(val) : val };
			};
			calc.packageLength = fixDim(calc.packageLength);
			calc.packageWidth = fixDim(calc.packageWidth);
			calc.packageHeight = fixDim(calc.packageHeight);
			calc.weightMajor = fixDim(calc.weightMajor);
			calc.weightMinor = fixDim(calc.weightMinor);
			calc.measurementSystem = (calc.measurementSystem || 'ENGLISH').toString().toUpperCase();
			normalized.calculatedShippingRate = calc;
		}

		return normalized;
	});

	return payload;
}

function json(body: any, status: number = 200) {
	return { statusCode: status, headers: { 'Content-Type': 'application/json' }, body: JSON.stringify(body) };
}

export const handler: Handler = async (event) => {
	try {
		// Verify caller has a bearer token and extract user sub
		const bearer = getBearerToken(event);
		let sub = (await requireAuthVerified(event))?.sub || null;
		if (!sub) sub = getJwtSubUnverified(event);
		if (!bearer || !sub) return json({ ok: false, error: 'Unauthorized' }, 401);

		// Load user's eBay refresh token
		const store = tokensStore();
		const saved = (await store.get(userScopedKey(sub, 'ebay.json'), { type: 'json' })) as any;
		const refresh = saved?.refresh_token as string | undefined;
		if (!refresh) return json({ ok: false, error: 'Connect eBay first' }, 400);

		// Mint user access token with sell.account scope for Account API
		const scopes = [
			'https://api.ebay.com/oauth/api_scope',
			'https://api.ebay.com/oauth/api_scope/sell.account',
		];
		const { access_token } = await accessTokenFromRefresh(refresh, scopes);

		const MARKETPLACE_ID = process.env.EBAY_MARKETPLACE_ID || 'EBAY_US';
		const { apiHost } = tokenHosts(process.env.EBAY_ENV);
		const headers = {
			Authorization: `Bearer ${access_token}`,
			Accept: 'application/json',
			'Content-Type': 'application/json',
			'Content-Language': 'en-US',
			'Accept-Language': 'en-US',
			'X-EBAY-C-MARKETPLACE-ID': MARKETPLACE_ID,
		} as Record<string, string>;

		// Build minimal, known-good payload
		const body = event.body ? JSON.parse(event.body) : {};
		const name = String(body.name || 'App Default USPS');
		const handlingTimeVal = Number(body.handlingTime ?? 3);
		const free = !!body.free;
		const costType = String(body.costType || (free ? 'FLAT_RATE' : 'CALCULATED')).toUpperCase();
	const serviceCode = String(body.serviceCode || (free ? 'USPSPriorityFlatRateBox' : 'USPSParcel'));
		const flatRate = body.flatRate != null ? String(Number(body.flatRate).toFixed(2)) : '5.99';
		const measurementSystem = (body.calcMeasurementSystem === 'METRIC') ? 'METRIC' : 'ENGLISH';
		const packageType = body.calcPackageType || 'PACKAGE_THICK_ENVELOPE';
		const toNum = (val: any, def: number) => {
			const n = Number(val);
			return Number.isFinite(n) && n >= 0 ? n : def;
		};
		const lengthVal = toNum(body.calcLength, measurementSystem === 'METRIC' ? 30 : 12);
		const widthVal = toNum(body.calcWidth, measurementSystem === 'METRIC' ? 20 : 9);
		const heightVal = toNum(body.calcHeight, measurementSystem === 'METRIC' ? 8 : 3);
		const weightMajor = toNum(body.calcWeightMajor, measurementSystem === 'METRIC' ? 1 : 1);
		const weightMinor = toNum(body.calcWeightMinor, 0);
		const dimUnit = measurementSystem === 'METRIC' ? 'CENTIMETER' : 'INCH';
		const majorUnit = measurementSystem === 'METRIC' ? 'KILOGRAM' : 'POUND';
		const minorUnit = measurementSystem === 'METRIC' ? 'GRAM' : 'OUNCE';


		let payload = {
			name,
			marketplaceId: MARKETPLACE_ID,
			categoryTypes: [{ name: 'ALL_EXCLUDING_MOTORS_VEHICLES', default: true }],
			handlingTime: { value: Math.max(0, isNaN(handlingTimeVal) ? 3 : handlingTimeVal), unit: 'DAY' },
			shippingOptions: [
				{
					optionType: 'DOMESTIC',
					costType: free ? 'FLAT_RATE' : costType,
					shippingServices: [
						{
							shippingCarrierCode: 'USPS',
							shippingServiceCode: serviceCode,
							freeShipping: free,
							...(free || costType === 'CALCULATED'
								? {}
								: { shippingCost: { value: flatRate, currency: 'USD' } }),
							sortOrder: 1,
							buyerResponsibleForShipping: false,
							buyerResponsibleForPickup: false,
						},
					],
					shipToLocations: { regionIncluded: [{ regionType: 'COUNTRY', regionName: 'US' }] },
					packageHandlingCost: { value: '0.00', currency: 'USD' },
					shippingDiscountProfileId: '0',
					shippingPromotionOffered: false,
					...(free || costType !== 'CALCULATED'
						? {}
						: {
								calculatedShippingRate: {
									measurementSystem,
									packageType,
									packageLength: { value: lengthVal.toString(), unit: dimUnit },
									packageWidth: { value: widthVal.toString(), unit: dimUnit },
									packageHeight: { value: heightVal.toString(), unit: dimUnit },
									weightMajor: { value: weightMajor.toString(), unit: majorUnit },
									weightMinor: { value: weightMinor.toString(), unit: minorUnit },
								},
							}),
				},
			],
			shipToLocations: { regionIncluded: [{ regionType: 'COUNTRY', regionName: 'US' }] },
			globalShipping: false,
			pickupDropOff: false,
			freightShipping: false,
		};
		payload = sanitizeFulfillmentPayload(payload);

		const url = `${apiHost}/sell/account/v1/fulfillment_policy`;
		const res = await fetch(url, { method: 'POST', headers, body: JSON.stringify(payload) });
		const txt = await res.text();
		let resBody: any; try { resBody = JSON.parse(txt); } catch { resBody = txt; }
		const www = res.headers.get('www-authenticate') || '';
		if (!res.ok) return json({ error: 'create-policy failed', status: res.status, wwwAuthenticate: www, detail: resBody, sent: payload }, res.status);
		return json({ ok: true, policy: resBody }, 200);
	} catch (e: any) {
		return json({ ok: false, error: 'policy-create fatal', detail: e?.message || String(e) }, 500);
	}
};
